interface ErrorBoundaryProps {
  children: React.ReactNode;
}

interface ErrorBoundaryState {
  hasError: boolean;
  error?: Error;
}

class ErrorBoundary extends Component<ErrorBoundaryProps, ErrorBoundaryState> {
  state: ErrorBoundaryState = { hasError: false };

  static getDerivedStateFromError(error: Error) {
    return { hasError: true, error };
  }

  componentDidCatch(error: any, errorInfo: any) {
    console.error("ErrorBoundary caught an error:", error, errorInfo);
    // You could also log this to an external service here
  }

  render() {
    const { hasError, error } = this.state;
    if (hasError) {
      return (
        <div className="min-h-screen bg-surface flex items-center justify-center p-8 text-center">
          <div className="bg-surface-container-lowest p-12 rounded-[3rem] ambient-shadow max-w-md border border-outline-variant/10">
            <div className="w-20 h-20 bg-primary/10 rounded-3xl flex items-center justify-center mx-auto mb-8">
              <AlertCircle className="w-10 h-10 text-primary" />
            </div>
            <h2 className="text-3xl font-display font-black text-on-surface mb-4 tracking-tight">
              ¡Vaya! Algo salió mal
            </h2>
            <p className="text-on-surface-variant/60 mb-10 font-medium leading-relaxed break-words">
              {error
                ? error.message
                : "Hemos detectado un error inesperado al renderizar los datos. No te preocupes, tus datos están a salvo. Pulsa el botón para reiniciar la aplicación."}
            </p>
            <button
              onClick={() => {
                localStorage.clear();
                window.location.href = "/";
              }}
              className="w-full py-5 primary-gradient text-white rounded-2xl font-black uppercase tracking-widest text-xs shadow-xl hover:scale-[1.02] transition-all"
            >
              Reiniciar Aplicación
            </button>
            <button
              onClick={() => (this as any).setState({ hasError: false })}
              className="mt-6 text-[10px] font-black text-on-surface-variant/40 uppercase tracking-widest hover:text-primary transition-colors"
            >
              Intentar recuperar
            </button>
          </div>
        </div>
      );
    }

    return (this as any).props.children;
  }
}

