const parseMarkdownToBlocks = (markdown: string) => {
  if (!markdown) return [];
  const rawBlocks = markdown.split(/\n\n+/);
  return rawBlocks.map((block) => {
    const id = Math.random().toString(36).substring(7);
    const trimmed = block.trim();
    if (trimmed.startsWith("# ")) {
      return { id, type: "h1", text: trimmed.replace(/^#\s+/, "") };
    }
    if (trimmed.startsWith("## ")) {
      return { id, type: "h2", text: trimmed.replace(/^##\s+/, "") };
    }
    if (trimmed.startsWith("### ")) {
      return { id, type: "h3", text: trimmed.replace(/^###\s+/, "") };
    }
    const imgMatch = trimmed.match(/^!\[(.*?)\]\((.*?)\)$/);
    if (imgMatch) {
      return { id, type: "image", url: imgMatch[2], alt: imgMatch[1] };
    }
    return { id, type: "text", text: trimmed };
  });
};

const stringifyBlocksToMarkdown = (blocks: any[]) => {
  return blocks
    .map((b) => {
      if (b.type === "h1") return `# ${b.text}`;
      if (b.type === "h2") return `## ${b.text}`;
      if (b.type === "h3") return `### ${b.text}`;
      if (b.type === "image") return `![${b.alt || ""}](${b.url})`;
      return b.text;
    })
    .join("\n\n");
};

const PageEditorModal = ({
  pageUrl,
  initialMarkdown,
  onClose,
  onSave,
}: any) => {
  const [blocks, setBlocks] = useState<any[]>(() => {
    const b = parseMarkdownToBlocks(initialMarkdown);
    if (b.length === 0)
      b.push({
        id: Math.random().toString(36).substring(7),
        type: "h1",
        text: "Nueva Página",
      });
    return b;
  });

  const [isUploading, setIsUploading] = useState(false);
  const fileInputRef = useRef<HTMLInputElement>(null);
  const [targetIndex, setTargetIndex] = useState(-1);

  const handleImageUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    setIsUploading(true);
    try {
      // Usar FileReader y un canvas para comprimir la imagen y guardar como base64
      // para evitar problemas de permisos con Firebase Storage si no está configurado.
      const reader = new FileReader();
      reader.readAsDataURL(file);
      reader.onload = (event) => {
        const img = new Image();
        img.src = event.target?.result as string;
        img.onload = () => {
          const canvas = document.createElement("canvas");
          const MAX_WIDTH = 800;
          let width = img.width;
          let height = img.height;

          if (width > MAX_WIDTH) {
            height = Math.round((height * MAX_WIDTH) / width);
            width = MAX_WIDTH;
          }

          canvas.width = width;
          canvas.height = height;
          const ctx = canvas.getContext("2d");
          ctx?.drawImage(img, 0, 0, width, height);

          // Comprimir a webp
          const base64Url = canvas.toDataURL("image/webp", 0.8);

          const newBlock = {
            id: Math.random().toString(36).substring(7),
            type: "image",
            url: base64Url,
            alt: file.name,
          };
          const newBlocks = [...blocks];
          if (targetIndex >= 0) {
            newBlocks[targetIndex] = newBlock; // replace the empty image block
          } else {
            newBlocks.push(newBlock);
          }
          setBlocks(newBlocks);
          setIsUploading(false);
          setTargetIndex(-1);
          if (fileInputRef.current) fileInputRef.current.value = "";
        };
        img.onerror = () => {
          setIsUploading(false);
          setTargetIndex(-1);
          alert("Error leyendo imagen");
        };
      };
    } catch (e) {
      console.error("Error uploading image", e);
      alert("Error subiendo imagen");
      setIsUploading(false);
      setTargetIndex(-1);
    }
  };

  const addBlock = (type: string, index: number) => {
    const newBlock =
      type === "image"
        ? {
            id: Math.random().toString(36).substring(7),
            type: "image",
            url: "",
            alt: "",
          }
        : { id: Math.random().toString(36).substring(7), type, text: "" };

    const newBlocks = [...blocks];
    newBlocks.splice(index + 1, 0, newBlock);
    setBlocks(newBlocks);
  };

  const updateBlock = (index: number, updates: any) => {
    const newBlocks = [...blocks];
    newBlocks[index] = { ...newBlocks[index], ...updates };
    setBlocks(newBlocks);
  };

  const moveBlock = (index: number, direction: "up" | "down") => {
    if (direction === "up" && index === 0) return;
    if (direction === "down" && index === blocks.length - 1) return;

    const newBlocks = [...blocks];
    const swapIndex = direction === "up" ? index - 1 : index + 1;
    [newBlocks[index], newBlocks[swapIndex]] = [
      newBlocks[swapIndex],
      newBlocks[index],
    ];
    setBlocks(newBlocks);
  };

  const deleteBlock = (index: number) => {
    const newBlocks = [...blocks];
    newBlocks.splice(index, 1);
    if (newBlocks.length === 0) {
      newBlocks.push({
        id: Math.random().toString(36).substring(7),
        type: "text",
        text: "",
      });
    }
    setBlocks(newBlocks);
  };

  return (
    <motion.div
      initial={{ opacity: 0 }}
      animate={{ opacity: 1 }}
      exit={{ opacity: 0 }}
      className="fixed inset-0 z-[100] bg-black/60 backdrop-blur-sm flex items-center justify-center p-4 lg:p-8"
    >
      <input
        type="file"
        ref={fileInputRef}
        onChange={handleImageUpload}
        className="hidden"
        accept="image/*"
      />

      <motion.div
        initial={{ opacity: 0, scale: 0.95, y: 10 }}
        animate={{ opacity: 1, scale: 1, y: 0 }}
        exit={{ opacity: 0, scale: 0.95, y: 10 }}
        className="bg-surface-container-lowest rounded-3xl w-full max-w-4xl h-[90vh] flex flex-col shadow-2xl relative overflow-hidden text-on-surface"
      >
        <div className="p-6 border-b border-outline-variant/10 flex items-center justify-between bg-surface-container-lowest shrink-0 z-20 shadow-sm">
          <div>
            <h2 className="text-xl font-bold font-display flex items-center gap-2">
              <Edit3 className="w-5 h-5 text-primary" /> Editar Página:{" "}
              {pageUrl}
            </h2>
            <p className="text-sm text-on-surface-variant flex items-center gap-1 mt-1">
              Añade y arrastra bloques de contenido.
            </p>
          </div>
          <button
            onClick={onClose}
            className="p-2 hover:bg-surface-container rounded-full text-on-surface-variant transition-colors"
          >
            <X className="w-6 h-6" />
          </button>
        </div>

        <div className="flex-1 overflow-y-auto p-4 md:p-8 space-y-6 bg-surface-container-lowest relative">
          <div
            className="absolute inset-0 bg-repeat bg-[length:24px_24px] pointer-events-none opacity-[0.02]"
            style={{
              backgroundImage:
                "radial-gradient(circle, #000 1px, transparent 1px)",
            }}
          />
          <div className="max-w-2xl mx-auto space-y-6 relative z-10">
            {blocks.map((block, index) => (
              <div
                key={block.id}
                className="group relative pr-12 animate-in slide-in-from-bottom-2 fade-in duration-200"
              >
                <div className="absolute top-0 right-0 h-full flex flex-col items-center justify-center gap-1 opacity-0 group-hover:opacity-100 transition-opacity translate-x-4 group-hover:translate-x-0 duration-200">
                  <button
                    onClick={() => moveBlock(index, "up")}
                    disabled={index === 0}
                    className="w-8 h-8 flex items-center justify-center hover:bg-surface-container rounded-full text-on-surface-variant disabled:opacity-30 transition-colors shadow-sm bg-white"
                    title="Subir bloque"
                  >
                    <ArrowUp className="w-4 h-4" />
                  </button>
                  <button
                    onClick={() => moveBlock(index, "down")}
                    disabled={index === blocks.length - 1}
                    className="w-8 h-8 flex items-center justify-center hover:bg-surface-container rounded-full text-on-surface-variant disabled:opacity-30 transition-colors shadow-sm bg-white"
                    title="Bajar bloque"
                  >
                    <ArrowDown className="w-4 h-4" />
                  </button>
                  <div className="h-2" />
                  <button
                    onClick={() => deleteBlock(index)}
                    className="w-8 h-8 flex items-center justify-center hover:bg-error hover:text-white rounded-full text-error transition-colors shadow-sm bg-error/10"
                    title="Eliminar bloque"
                  >
                    <Trash2 className="w-4 h-4" />
                  </button>
                </div>

                {block.type === "h1" && (
                  <input
                    className="w-full text-4xl lg:text-5xl font-black font-display bg-transparent outline-none focus:bg-surface-container-low focus:ring-2 focus:ring-primary/20 rounded-2xl px-6 py-4 transition-all placeholder:opacity-30"
                    value={block.text}
                    onChange={(e) =>
                      updateBlock(index, { text: e.target.value })
                    }
                    placeholder="Título Principal"
                  />
                )}
                {block.type === "h2" && (
                  <input
                    className="w-full text-2xl lg:text-3xl font-bold bg-transparent outline-none focus:bg-surface-container-low focus:ring-2 focus:ring-primary/20 rounded-2xl px-6 py-4 transition-all placeholder:opacity-30"
                    value={block.text}
                    onChange={(e) =>
                      updateBlock(index, { text: e.target.value })
                    }
                    placeholder="Subtítulo"
                  />
                )}
                {block.type === "h3" && (
                  <input
                    className="w-full text-xl font-bold bg-transparent outline-none focus:bg-surface-container-low focus:ring-2 focus:ring-primary/20 rounded-2xl px-6 py-3 transition-all placeholder:opacity-30"
                    value={block.text}
                    onChange={(e) =>
                      updateBlock(index, { text: e.target.value })
                    }
                    placeholder="Encabezado pequeño"
                  />
                )}
                {block.type === "text" && (
                  <textarea
                    className="w-full text-base lg:text-lg font-medium leading-relaxed bg-surface-container/30 outline-none focus:ring-2 focus:ring-primary/20 rounded-3xl p-6 shadow-sm min-h-[160px] resize-y placeholder:opacity-30 border border-outline-variant/10 focus:bg-white transition-all"
                    value={block.text}
                    onChange={(e) => {
                      e.target.style.height = "auto";
                      e.target.style.height = `${e.target.scrollHeight}px`;
                      updateBlock(index, { text: e.target.value });
                    }}
                    placeholder="Escribe el texto aquí... (Soporta Markdown: **negrita**, *cursiva*, [enlaces](url))"
                  />
                )}
                {block.type === "image" && (
                  <div className="w-full bg-white rounded-3xl p-4 shadow-sm border border-outline-variant/10 flex flex-col gap-4">
                    {block.url ? (
                      <div className="relative group/img overflow-hidden rounded-2xl bg-surface-container-lowest">
                        <img
                          src={block.url}
                          alt={block.alt || "Imagen de la página"}
                          className="w-full max-h-[500px] object-cover transition-transform duration-500 group-hover/img:scale-105"
                        />
                        <div className="absolute inset-0 bg-black/40 opacity-0 group-hover/img:opacity-100 transition-opacity flex items-center justify-center gap-4">
                          <button
                            onClick={() => updateBlock(index, { url: "" })}
                            className="p-3 bg-red-500 text-white rounded-full hover:bg-red-600 transition-colors shadow-lg hover:scale-110 active:scale-95"
                            title="Eliminar imagen"
                          >
                            <Trash2 className="w-5 h-5" />
                          </button>
                        </div>
                      </div>
                    ) : (
                      <div className="flex flex-col items-center justify-center p-12 border-2 border-dashed border-outline-variant/30 rounded-2xl gap-4 bg-surface-container/30 hover:bg-surface-container transition-colors">
                        <ImageIcon className="w-10 h-10 text-primary/50" />
                        <p className="text-sm font-bold text-on-surface">
                          Inserta una imagen para tu contenido
                        </p>
                        <div className="flex gap-2 w-full max-w-[280px]">
                          <button
                            onClick={() => {
                              setTargetIndex(index);
                              fileInputRef.current?.click();
                            }}
                            className="flex-1 py-3 bg-primary text-white text-sm font-bold rounded-xl hover:bg-primary/90 flex items-center justify-center gap-2 shadow-md shadow-primary/20 transition-all active:scale-95"
                            disabled={isUploading}
                          >
                            {isUploading && targetIndex === index ? (
                              <Loader2 className="w-5 h-5 animate-spin" />
                            ) : (
                              <Upload className="w-5 h-5" />
                            )}
                            Subir imagen
                          </button>
                        </div>
                        <div className="w-full max-w-[280px] mt-2 flex items-center gap-3">
                          <div className="h-px bg-outline-variant/20 flex-1"></div>
                          <span className="text-[10px] font-black text-on-surface-variant uppercase tracking-widest">
                            O pega URL
                          </span>
                          <div className="h-px bg-outline-variant/20 flex-1"></div>
                        </div>
                        <input
                          type="text"
                          className="w-full max-w-[280px] px-4 py-3 rounded-xl bg-white text-sm border-none shadow-inner focus:ring-2 focus:ring-primary/40 outline-none placeholder:opacity-40"
                          placeholder="https://..."
                          onKeyDown={(e) => {
                            if (e.key === "Enter" && e.currentTarget.value) {
                              updateBlock(index, {
                                url: e.currentTarget.value,
                              });
                            }
                          }}
                        />
                      </div>
                    )}
                  </div>
                )}

                {/* Add block menu below */}
                <div className="absolute -bottom-4 left-1/2 -translate-x-1/2 opacity-0 group-hover:opacity-100 transition-all z-20 flex gap-2 bg-on-surface text-surface shadow-xl rounded-full p-1.5 hover:scale-105 duration-200">
                  <button
                    onClick={() => addBlock("text", index)}
                    className="p-2 hover:bg-surface/20 rounded-full transition-colors tooltip-trigger"
                    title="Añadir Texto"
                  >
                    <Type className="w-4 h-4" />
                  </button>
                  <button
                    onClick={() => addBlock("h2", index)}
                    className="p-2 hover:bg-surface/20 rounded-full transition-colors tooltip-trigger"
                    title="Añadir Subtítulo"
                  >
                    <Heading2 className="w-4 h-4" />
                  </button>
                  <button
                    onClick={() => addBlock("image", index)}
                    className="p-2 hover:bg-surface/20 rounded-full transition-colors tooltip-trigger"
                    title="Añadir Imagen"
                  >
                    <ImageIcon className="w-4 h-4" />
                  </button>
                </div>
              </div>
            ))}

            <div className="pt-8 pb-12 flex justify-center sticky bottom-0">
              <div className="flex gap-2 bg-surface shadow-2xl border border-outline-variant/10 rounded-full p-2 animate-bounce-slight">
                <button
                  onClick={() => addBlock("text", blocks.length - 1)}
                  className="px-4 py-2 hover:bg-surface-container rounded-full transition-colors text-sm font-bold flex items-center gap-2"
                >
                  <Type className="w-4 h-4 text-primary" /> Párrafo
                </button>
                <button
                  onClick={() => addBlock("h2", blocks.length - 1)}
                  className="px-4 py-2 hover:bg-surface-container rounded-full transition-colors text-sm font-bold flex items-center gap-2"
                >
                  <Heading2 className="w-4 h-4 text-primary" /> Título
                </button>
                <button
                  onClick={() => addBlock("image", blocks.length - 1)}
                  className="px-4 py-2 hover:bg-surface-container rounded-full transition-colors text-sm font-bold flex items-center gap-2"
                >
                  <ImageIcon className="w-4 h-4 text-primary" /> Imagen
                </button>
              </div>
            </div>
          </div>
        </div>

        <div className="p-6 border-t border-outline-variant/10 flex justify-end gap-3 bg-surface-container-lowest shrink-0 z-20 shadow-[0_-4px_20px_rgb(0,0,0,0.05)]">
          <button
            onClick={onClose}
            className="px-6 py-3 bg-surface-container text-on-surface rounded-xl text-sm font-bold hover:bg-surface-container-high transition-colors"
          >
            Cancelar
          </button>
          <button
            onClick={() => {
              const markdown = stringifyBlocksToMarkdown(
                blocks.filter((b) => b.type !== "image" || b.url),
              );
              onSave(markdown);
            }}
            className="px-8 py-3 bg-[#005a54] text-white rounded-xl text-sm font-bold hover:bg-[#004a44] transition-colors shadow-lg shadow-[#005a54]/30"
          >
            Guardar Cambios
          </button>
        </div>
      </motion.div>
    </motion.div>
  );
};

export const formatDate = (dateNum: number) => {
  return new Intl.DateTimeFormat("es-ES", {
    year: "numeric",
    month: "long",
    day: "numeric",
  }).format(new Date(dateNum));
};

const BlogListPage = () => {
  const [posts, setPosts] = useState<BlogPost[]>([]);
  const [loading, setLoading] = useState(true);
  const [selectedCategory, setSelectedCategory] = useState<string | null>(null);

  useEffect(() => {
    const fetchPosts = async () => {
      try {
        const postsQuery = query(
          collection(db, "blog_posts"),
          where("published", "==", true),
        );
        const snapshot = await getDocs(postsQuery);
        const fetchedPosts = snapshot.docs.map((doc) => ({
          ...doc.data(),
          id: doc.id,
        })) as BlogPost[];

        // Sort by date manually if index not present
        fetchedPosts.sort((a, b) => b.createdAt - a.createdAt);
        setPosts(fetchedPosts);
      } catch (err) {
        console.error("Error fetching blog posts:", err);
      } finally {
        setLoading(false);
      }
    };
    fetchPosts();
  }, []);

  if (loading) {
    return (
      <div className="flex-1 flex justify-center items-center min-h-[50vh]">
        <Loader2 className="w-12 h-12 text-primary animate-spin" />
      </div>
    );
  }

  const categories = Array.from(
    new Set(posts.map((p) => p.category).filter(Boolean)),
  ) as string[];
  const displayedPosts = selectedCategory
    ? posts.filter((p) => p.category === selectedCategory)
    : posts;

  return (
    <div className="flex-1 max-w-7xl mx-auto px-4 sm:px-6 w-full pt-8 pb-32">
      <div className="mb-12 border-b-2 border-outline-variant pb-6 flex flex-col sm:flex-row sm:items-baseline justify-between gap-4">
        <h1 className="text-4xl md:text-5xl font-display font-black text-[#00675b] bg-white tracking-tight">
          noticias
        </h1>
        <select
          value={selectedCategory || ""}
          onChange={(e) => setSelectedCategory(e.target.value || null)}
          className="px-4 py-2 bg-surface-container-low border border-outline-variant/30 rounded-xl text-on-surface font-medium outline-none focus:ring-2 focus:ring-primary/20 cursor-pointer"
        >
          <option value="">Todas las categorías</option>
          {categories.map((cat) => (
            <option key={cat} value={cat}>
              {cat}
            </option>
          ))}
        </select>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-x-6 gap-y-12">
        {displayedPosts.map((post, idx) => {
          const isFeatured = idx === 0;
          return (
            <Link
              key={post.id}
              to={`/blog/${post.id}`}
              className={cn(
                "group flex flex-col focus:outline-none focus-visible:ring-2 focus-visible:ring-primary",
                isFeatured ? "md:col-span-2 lg:col-span-2 row-span-2" : "",
              )}
            >
              <div className="relative overflow-hidden w-full bg-surface-container-low mb-4">
                <img
                  src={
                    post.imageUrl ||
                    "https://images.unsplash.com/photo-1522202176988-66273c2fd55f?auto=format&fit=crop&q=80&w=1200"
                  }
                  alt={post.title}
                  className={cn(
                    "w-full object-cover transition-transform duration-500 group-hover:scale-105",
                    isFeatured ? "h-64 sm:h-[400px]" : "h-48",
                  )}
                />
                {post.category && (
                  <div className="absolute top-4 left-4 bg-[#00675b] text-white text-[10px] font-black uppercase tracking-widest px-3 py-1 shadow-sm">
                    {post.category}
                  </div>
                )}
              </div>
              <div className="flex-1 flex flex-col justify-start px-2">
                <div className="text-xs text-on-surface-variant font-bold uppercase tracking-wider mb-2">
                  {formatDate(post.createdAt)}
                </div>
                <h2
                  className={cn(
                    "font-display font-black text-on-surface leading-tight tracking-tight mb-2 group-hover:text-[#00675b] transition-colors",
                    isFeatured ? "text-2xl sm:text-4xl" : "text-xl",
                  )}
                >
                  {post.title}
                </h2>
                {(isFeatured || post.summary) && (
                  <p
                    className={cn(
                      "text-on-surface-variant/80 font-medium leading-relaxed line-clamp-3 mt-1",
                      isFeatured ? "text-base sm:text-lg" : "text-sm",
                    )}
                  >
                    {post.summary || post.content.substring(0, 150) + "..."}
                  </p>
                )}
              </div>
            </Link>
          );
        })}
        {displayedPosts.length === 0 && (
          <div className="col-span-full py-20 text-center">
            <div className="w-16 h-16 bg-surface-container-low rounded-full flex items-center justify-center mx-auto mb-4">
              <FileText className="w-8 h-8 text-on-surface-variant/40" />
            </div>
            <p className="text-on-surface-variant text-lg">
              No hay noticias publicadas aún.
            </p>
          </div>
        )}
      </div>
    </div>
  );
};

const BlogPostPage = () => {
  const { id } = useParams<{ id: string }>();
  const [post, setPost] = useState<BlogPost | null>(null);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    const fetchPost = async () => {
      if (!id) return;
      try {
        const docRef = doc(db, "blog_posts", id);
        const docSnap = await getDoc(docRef);
        if (docSnap.exists()) {
          setPost({ ...docSnap.data(), id: docSnap.id } as BlogPost);
        }
      } catch (err) {
        console.error("Error fetching blog post:", err);
      } finally {
        setLoading(false);
      }
    };
    fetchPost();
  }, [id]);

  if (loading) {
    return (
      <div className="flex-1 flex justify-center items-center min-h-[50vh]">
        <Loader2 className="w-12 h-12 text-primary animate-spin" />
      </div>
    );
  }

  if (!post || !post.published) {
    return (
      <div className="flex-1 flex flex-col justify-center items-center py-32 text-center px-4">
        <h1 className="text-4xl md:text-6xl font-display font-black text-on-surface mb-4">
          Artículo no encontrado
        </h1>
        <p className="text-on-surface-variant text-lg max-w-md mx-auto mb-8">
          El artículo que buscas no existe o ha sido eliminado.
        </p>
        <Link
          to="/blog"
          className="px-6 py-3 bg-primary text-white rounded-xl font-bold hover:bg-primary/90 transition-colors"
        >
          Volver a Noticias
        </Link>
      </div>
    );
  }

  return (
    <div className="flex-1 max-w-4xl mx-auto px-4 sm:px-6 pt-12 pb-32">
      <Link
        to="/blog"
        className="inline-flex items-center text-sm font-bold text-on-surface-variant hover:text-primary mb-8 transition-colors uppercase tracking-wider"
      >
        <ArrowUp className="w-4 h-4 mr-2 transform -rotate-90" />
        Volver a Noticias
      </Link>
      <div className="mb-8">
        <span className="inline-block bg-[#00675b] text-white text-xs font-black uppercase tracking-widest px-4 py-1.5 mb-6 shadow-sm">
          {post.category || "Actualidad"}
        </span>
        <h1 className="text-4xl sm:text-5xl md:text-7xl font-display font-black text-on-surface leading-[1.05] tracking-tighter mb-4 break-words text-wrap balance-text">
          {post.title}
        </h1>
        {post.summary && (
          <p className="text-xl sm:text-2xl text-on-surface-variant font-medium leading-relaxed mb-8">
            {post.summary}
          </p>
        )}
        <div className="flex items-center gap-4 text-sm font-bold text-on-surface-variant border-y border-outline-variant/10 py-4 uppercase tracking-wider">
          <span>
            Por: <span className="text-on-surface">{post.authorName}</span>
          </span>
          <span className="w-1 h-1 rounded-full bg-outline-variant/30"></span>
          <span>{formatDate(post.createdAt)}</span>
        </div>
      </div>

      {post.imageUrl && (
        <div className="w-full mb-12 aspect-video bg-surface-container-low rounded-[2rem] overflow-hidden">
          <img
            src={post.imageUrl}
            alt={post.title}
            className="w-full h-full object-cover"
          />
        </div>
      )}

      <div className="prose prose-lg md:prose-xl prose-p:leading-relaxed prose-headings:font-display prose-headings:font-black prose-headings:tracking-tight max-w-none prose-a:text-primary hover:prose-a:text-primary/80 prose-img:rounded-3xl prose-img:shadow-xl mt-8">
        <Markdown>{post.content}</Markdown>
      </div>
    </div>
  );
};

const StaticPageView = ({
  footerConfig,
  user,
  onSaveConfig,
}: {
  footerConfig: FooterConfig;
  user: UserProfile | null;
  onSaveConfig: (newConfig: FooterConfig) => Promise<void>;
}) => {
  const { slug: rawSlug } = useParams<{ slug: string }>();
  const slug = decodeURIComponent(rawSlug || "");
  console.log("StaticPageView rendering with slug:", slug);

  useEffect(() => {
    console.log("StaticPageView scrolling to top");
    window.scrollTo(0, 0);
  }, [slug]);

  const pageUrl = `#page-${slug}`;
  const possibleOldUrl = `/pagina/${slug}`;
  const content =
    footerConfig?.pages?.[pageUrl] || footerConfig?.pages?.[possibleOldUrl];

  console.log(
    "StaticPageView content length:",
    content?.length,
    "isAdmin:",
    (user?.role === "admin" || user?.email === "daviidjg1991@gmail.com"),
  );

  const isAdmin = (user?.role === "admin" || user?.email === "daviidjg1991@gmail.com");
  const [isEditing, setIsEditing] = useState(false);
  const linkLabel =
    footerConfig.columns
      .flatMap((c) => c.links)
      .find((l) => l.url === pageUrl || l.url === possibleOldUrl)?.label ||
    "Página";

  return (
    <div className="flex-1 w-full max-w-4xl mx-auto flex flex-col pt-8 pb-32 px-4 sm:px-6">
      <div className="flex items-center justify-between mb-8 pb-4 border-b border-outline-variant/10">
        <h1 className="hidden">{linkLabel}</h1>
        {isAdmin && !isEditing && (
          <button
            onClick={() => setIsEditing(true)}
            className="px-5 py-2.5 bg-surface-container-low hover:bg-surface-container rounded-xl text-primary text-sm font-bold flex items-center gap-2 transition-colors"
          >
            <Edit3 className="w-4 h-4" /> Editar
          </button>
        )}
      </div>

      <div className="flex-1 relative">
        {!content && !isAdmin ? (
          <div className="text-center py-32 bg-surface-container-lowest rounded-3xl border border-outline-variant/10">
            <h2 className="text-3xl font-bold text-on-surface mb-4">
              Página en blanco
            </h2>
            <p className="text-on-surface-variant">
              Esta página aún no contiene información.
            </p>
          </div>
        ) : !content && isAdmin && !isEditing ? (
          <div className="text-center py-32 flex flex-col items-center bg-surface-container-lowest rounded-3xl border border-outline-variant/10">
            <h2 className="text-2xl font-bold text-on-surface mb-2">
              Página en blanco
            </h2>
            <p className="text-[10px] text-red-500 font-mono mb-2">
              URL: {pageUrl}
            </p>
            <p className="text-on-surface-variant mb-6">
              No hay contenido. Inicia la edición ahora.
            </p>
            <button
              onClick={() => setIsEditing(true)}
              className="px-8 py-4 bg-primary text-white font-bold rounded-xl shadow-lg hover:bg-primary/90 flex items-center gap-2"
            >
              <Edit3 className="w-5 h-5" /> Crear Contenido
            </button>
          </div>
        ) : (
          !isEditing && (
            <div className="prose prose-on-surface prose-lg max-w-none prose-headings:font-bold prose-a:text-primary hover:prose-a:text-primary/80 prose-img:rounded-3xl prose-img:shadow-md bg-surface-container-lowest p-8 sm:p-12 rounded-3xl border border-outline-variant/10">
              <Markdown urlTransform={(url) => url}>{content}</Markdown>
            </div>
          )
        )}

        <AnimatePresence>
          {isEditing && (
            <PageEditorModal
              pageUrl={pageUrl}
              initialMarkdown={content || ""}
              onClose={() => setIsEditing(false)}
              onSave={async (markdown: string) => {
                const newPages = { ...(footerConfig.pages || {}) };
                newPages[pageUrl] = markdown;
                const old = possibleOldUrl;
                if (pageUrl !== old && newPages[old]) delete newPages[old];

                const newConfig = {
                  ...footerConfig,
                  pages: newPages,
                };
                await onSaveConfig(newConfig);
                setIsEditing(false);
              }}
            />
          )}
        </AnimatePresence>
      </div>
    </div>
  );
};

const AdminPromotionsTab = ({ users }: { users: any[] }) => {
  const { config, updateConfig } = usePromotionsConfig();
  const [editingPromoId, setEditingPromoId] = useState<string | null>(null);
  const [formData, setFormData] = useState<any>(null);
  const [isSaving, setIsSaving] = useState(false);

  const handleSave = async () => {
    setIsSaving(true);
    try {
      let newPromotions = [...config.promotions];
      if (editingPromoId === "new") {
        newPromotions.push({ ...formData, id: Date.now().toString() });
      } else {
        newPromotions = newPromotions.map((p) => p.id === editingPromoId ? formData : p);
      }
      await updateConfig({ promotions: newPromotions });
      setEditingPromoId(null);
      alert("Promoción guardada exitosamente");
    } catch (error) {
      console.error(error);
      alert("Error al guardar promoción");
    } finally {
      setIsSaving(false);
    }
  };

  const handleDelete = async (id: string) => {
    if (confirm("¿Estás seguro de eliminar esta promoción?")) {
      const newPromotions = config.promotions.filter((p: any) => p.id !== id);
      try {
        await updateConfig({ promotions: newPromotions });
      } catch (error) {
        console.error(error);
        alert("Error al eliminar promoción");
      }
    }
  };

  return (
    <div className="bg-surface-container-lowest p-8 rounded-[2rem] border border-outline-variant/10">
      <div className="flex items-center justify-between mb-8">
        <div>
          <h2 className="text-2xl font-black flex items-center gap-2">
            <Zap className="w-6 h-6 text-primary" />
            Promociones y Ofertas
          </h2>
          <p className="text-on-surface-variant mt-1">
            Configura incentivos para los nuevos usuarios.
          </p>
        </div>
        {!editingPromoId && (
          <button
            onClick={() => {
              setFormData({
                name: "Nueva Promoción",
                isActive: false,
                userRangeStart: 1,
                userRangeEnd: 100,
                planDurationMonths: 12,
                planType: "Premium Pro",
                targetAudience: "professional"
              });
              setEditingPromoId("new");
            }}
            className="flex items-center gap-2 px-4 py-2 bg-primary text-white rounded-xl font-bold hover:bg-primary/90 transition-colors"
          >
            <Plus className="w-4 h-4" />
            Crear Promoción
          </button>
        )}
      </div>

      {!editingPromoId ? (
        <div className="grid grid-cols-1 gap-4">
          {config.promotions.map((promo: any) => {
            const claimedUsersCount = users.filter((u: any) => u.hasClaimedPromotion && (u.claimedPromotionId === promo.id || promo.id === "default")).length;
            return (
              <div key={promo.id} className="bg-surface-container p-6 rounded-2xl flex flex-col md:flex-row md:items-center justify-between gap-4">
                <div className="flex items-center gap-4">
                  <div className={`w-12 h-12 rounded-xl flex items-center justify-center shrink-0 ${promo.isActive ? 'bg-green-500/20 text-green-600' : 'bg-red-500/20 text-red-600'}`}>
                    <Zap className="w-6 h-6" />
                  </div>
                  <div>
                    <h3 className="font-bold text-lg">{promo.name || "Promoción"}</h3>
                    <p className="text-sm text-on-surface-variant flex items-center gap-2 mt-1">
                      <Users className="w-4 h-4" /> {claimedUsersCount} / {promo.userRangeEnd - promo.userRangeStart + 1} usuarios (Rango: {promo.userRangeStart} - {promo.userRangeEnd})
                      <span className="mx-2">•</span>
                      <Crown className="w-4 h-4" /> {promo.planType} ({promo.planDurationMonths} meses)
                    </p>
                  </div>
                </div>
                <div className="flex items-center gap-2 shrink-0">
                  <button
                    onClick={() => {
                      setFormData({ ...promo });
                      setEditingPromoId(promo.id);
                    }}
                    className="p-2 text-primary hover:bg-primary/10 rounded-lg transition-colors"
                  >
                    <Edit3 className="w-5 h-5" />
                  </button>
                  <button
                    onClick={() => handleDelete(promo.id)}
                    className="p-2 text-error hover:bg-error/10 rounded-lg transition-colors"
                  >
                    <Trash2 className="w-5 h-5" />
                  </button>
                </div>
              </div>
            );
          })}
          {config.promotions.length === 0 && (
            <div className="text-center py-12 text-on-surface-variant">
              No hay promociones configuradas.
            </div>
          )}
        </div>
      ) : (
        <div className="bg-surface-container p-6 rounded-2xl space-y-4">
          <h3 className="font-bold text-lg mb-4">
            {editingPromoId === "new" ? "Nueva Promoción" : "Editar Promoción"}
          </h3>
          
          <div className="grid grid-cols-1 gap-4 mb-4">
            <div>
              <label className="block text-xs font-bold text-on-surface-variant mb-1 uppercase tracking-wider">
                Nombre de la Promoción
              </label>
              <input
                type="text"
                value={formData.name || ""}
                onChange={(e) => setFormData({...formData, name: e.target.value})}
                className="w-full px-4 py-3 bg-surface rounded-xl border border-outline-variant focus:border-primary focus:ring-1 focus:ring-primary outline-none transition-all"
                placeholder="Ej. Promo Lanzamiento"
              />
            </div>
          </div>

          <div className="flex items-center gap-2 mb-4">
            <input 
              type="checkbox" 
              id="isActive"
              checked={formData.isActive}
              onChange={(e) => setFormData({...formData, isActive: e.target.checked})}
              className="w-4 h-4 text-primary rounded border-outline"
            />
            <label htmlFor="isActive" className="font-medium text-sm">Promoción Activa</label>
          </div>
          
          <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
            <div className="flex gap-2">
              <div className="flex-1">
                <label className="block text-xs font-bold text-on-surface-variant mb-1 uppercase tracking-wider">
                  Usuario Inicial
                </label>
                <input
                  type="number"
                  value={formData.userRangeStart || 1}
                  onChange={(e) => setFormData({...formData, userRangeStart: parseInt(e.target.value) || 1})}
                  className="w-full px-4 py-3 bg-surface rounded-xl border border-outline-variant focus:border-primary focus:ring-1 focus:ring-primary outline-none transition-all"
                />
              </div>
              <div className="flex-1">
                <label className="block text-xs font-bold text-on-surface-variant mb-1 uppercase tracking-wider">
                  Usuario Final
                </label>
                <input
                  type="number"
                  value={formData.userRangeEnd || 100}
                  onChange={(e) => setFormData({...formData, userRangeEnd: parseInt(e.target.value) || 0})}
                  className="w-full px-4 py-3 bg-surface rounded-xl border border-outline-variant focus:border-primary focus:ring-1 focus:ring-primary outline-none transition-all"
                />
              </div>
            </div>
            <div>
              <label className="block text-xs font-bold text-on-surface-variant mb-1 uppercase tracking-wider">
                Duración del Plan (Meses)
              </label>
              <input
                type="number"
                value={formData.planDurationMonths}
                onChange={(e) => setFormData({...formData, planDurationMonths: parseInt(e.target.value) || 0})}
                className="w-full px-4 py-3 bg-surface rounded-xl border border-outline-variant focus:border-primary focus:ring-1 focus:ring-primary outline-none transition-all"
              />
            </div>
            <div className="md:col-span-2">
              <label className="block text-xs font-bold text-on-surface-variant mb-1 uppercase tracking-wider">
                Público Objetivo
              </label>
              <select
                value={formData.targetAudience || "professional"}
                onChange={(e) => setFormData({...formData, targetAudience: e.target.value})}
                className="w-full px-4 py-3 bg-surface rounded-xl border border-outline-variant focus:border-primary focus:ring-1 focus:ring-primary outline-none transition-all mb-4"
              >
                <option value="professional">Solo Profesionales</option>
                <option value="user">Solo Particulares</option>
                <option value="both">Ambos (Profesionales y Particulares)</option>
              </select>

              <label className="block text-xs font-bold text-on-surface-variant mb-1 uppercase tracking-wider">
                Tipo de Plan
              </label>
              <select
                value={formData.planType}
                onChange={(e) => setFormData({...formData, planType: e.target.value})}
                className="w-full px-4 py-3 bg-surface rounded-xl border border-outline-variant focus:border-primary focus:ring-1 focus:ring-primary outline-none transition-all"
              >
                <option value="Premium Pro">Premium Pro</option>
                <option value="Pro">Pro</option>
                <option value="Premium">Premium</option>
              </select>
            </div>
          </div>
          
          <div className="flex justify-end gap-3 mt-6 pt-4 border-t border-outline-variant/20">
            <button
              onClick={() => setEditingPromoId(null)}
              className="px-4 py-2 font-bold text-on-surface-variant hover:bg-surface-container-highest rounded-xl transition-colors"
            >
              Cancelar
            </button>
            <button
              onClick={handleSave}
              disabled={isSaving}
              className="px-6 py-2 bg-primary text-white font-bold rounded-xl hover:bg-primary/90 transition-colors flex items-center gap-2"
            >
              {isSaving ? <Loader2 className="w-4 h-4 animate-spin" /> : <Save className="w-4 h-4" />}
              Guardar Cambios
            </button>
          </div>
        </div>
      )}
    </div>
  );
};


const AdminProPlansTab = ({ users }: { users: any[] }) => {
  const { plans, isEnabled } = useProPlansConfig();
  const [editingPlan, setEditingPlan] = useState<any | null>(null);
  const [subscriberCounts, setSubscriberCounts] = useState<{
    [key: string]: number;
  }>({});
  const [lastUpdated, setLastUpdated] = useState<number | null>(null);
  const [isQuarterly, setIsQuarterly] = useState(false);

  useEffect(() => {
    const fetchStats = async () => {
      const statsRef = doc(db, "settings", "pro_plans_stats");
      const docSnap = await getDoc(statsRef);
      const now = Date.now();

      let needsUpdate = true;
      if (docSnap.exists()) {
        const data = docSnap.data();
        if (now - data.lastUpdated < 3 * 60 * 60 * 1000) {
          needsUpdate = false;
          setSubscriberCounts(data.counts);
          setLastUpdated(data.lastUpdated);
        }
      }

      if (needsUpdate && users && users.length > 0) {
        // Calculate new stats
        const counts: any = {};
        plans.forEach((p) => (counts[p.id] = 0));
        users.forEach((u) => {
          const planId = u.professionalInfo?.plan || "basic";
          if (u.role === "professional" && counts[planId] !== undefined) {
            counts[planId]++;
          } else if (u.role === "professional") {
            counts[planId] = 1;
          }
        });
        setSubscriberCounts(counts);
        setLastUpdated(now);
      }
    };
    fetchStats();
  }, [users, plans]);

  const handleSave = async (e: React.FormEvent) => {
    e.preventDefault();
    const updatedPlans = plans.map((p) => {
      if (p.id === editingPlan.id) {
        return editingPlan;
      }
      // If the editing plan is marked as recommended, remove it from other plans
      if (editingPlan.isRecommended) {
        return { ...p, isRecommended: false };
      }
      return p;
    });
    try {
      await setDoc(
        doc(db, "settings", "pro_plans_config"),
        { plans: updatedPlans },
        { merge: true },
      );
      alert("Plan guardado y actualizado para todos los usuarios.");
      setEditingPlan(null);
    } catch (err) {
      console.error("Error saving plan:", err);
      alert("Error al guardar configuración del plan.");
    }
  };

  const handleToggleVisibility = async () => {
    try {
      await setDoc(
        doc(db, "settings", "pro_plans_config"),
        { isEnabled: !isEnabled },
        { merge: true },
      );
    } catch (err) {
      console.error("Error toggling plans:", err);
      alert("Error al actualizar visibilidad de los planes.");
    }
  };

  const handleAddFeature = () => {
    setEditingPlan({
      ...editingPlan,
      features: [...editingPlan.features, "Nueva característica"],
    });
  };

  const handleRemoveFeature = (index: number) => {
    const newFeatures = [...editingPlan.features];
    newFeatures.splice(index, 1);
    setEditingPlan({ ...editingPlan, features: newFeatures });
  };

  const handleFeatureChange = (index: number, value: string) => {
    const newFeatures = [...editingPlan.features];
    newFeatures[index] = value;
    setEditingPlan({ ...editingPlan, features: newFeatures });
  };

  if (editingPlan) {
    return (
      <div className="bg-surface-container-lowest p-8 rounded-xl border border-outline-variant/10">
        <div className="flex justify-between items-center mb-6 border-b border-outline-variant/10 pb-4">
          <h2 className="text-xl font-bold font-display">
            Editar Plan: {editingPlan.name}
          </h2>
          <button
            onClick={() => setEditingPlan(null)}
            className="text-sm font-medium text-on-surface-variant hover:text-on-surface"
          >
            Cancelar
          </button>
        </div>
        <form onSubmit={handleSave} className="space-y-6 max-w-2xl">
          <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
            <div>
              <label className="block text-xs font-bold uppercase tracking-wider text-on-surface-variant mb-2">
                Nombre del Plan
              </label>
              <input
                type="text"
                className="input-field"
                value={editingPlan.name}
                onChange={(e) =>
                  setEditingPlan({ ...editingPlan, name: e.target.value })
                }
              />
            </div>
            <div></div>
          </div>
          <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
            <div>
              <label className="block text-xs font-bold uppercase tracking-wider text-on-surface-variant mb-2">
                Precio Mensual (€)
              </label>
              <input
                type="number"
                className="input-field"
                value={editingPlan.price}
                onChange={(e) =>
                  setEditingPlan({
                    ...editingPlan,
                    price: Number(e.target.value),
                  })
                }
              />
            </div>
            <div>
              <label className="block text-xs font-bold uppercase tracking-wider text-on-surface-variant mb-2">
                Catálogo Mensual Comparativo (€)
              </label>
              <input
                type="number"
                className="input-field"
                value={editingPlan.comparePrice || ""}
                onChange={(e) =>
                  setEditingPlan({
                    ...editingPlan,
                    comparePrice: e.target.value ? Number(e.target.value) : undefined,
                  })
                }
                placeholder="Ej. 15 (opcional)"
              />
            </div>
            <div>
              <label className="block text-xs font-bold uppercase tracking-wider text-on-surface-variant mb-2">
                Precio Trimestral (€)
              </label>
              <input
                type="number"
                className="input-field"
                value={editingPlan.priceQuarterly || 0}
                onChange={(e) =>
                  setEditingPlan({
                    ...editingPlan,
                    priceQuarterly: Number(e.target.value),
                  })
                }
              />
            </div>
            <div>
              <label className="block text-xs font-bold uppercase tracking-wider text-on-surface-variant mb-2">
                Catálogo Trimestral Comparativo (€)
              </label>
              <input
                type="number"
                className="input-field"
                value={editingPlan.comparePriceQuarterly || ""}
                onChange={(e) =>
                  setEditingPlan({
                    ...editingPlan,
                    comparePriceQuarterly: e.target.value ? Number(e.target.value) : undefined,
                  })
                }
                placeholder="Ej. 30 (opcional)"
              />
            </div>
          </div>
          <div className="flex items-center gap-3 pt-2">
            <input
              type="checkbox"
              id="isRecommended"
              checked={!!editingPlan.isRecommended}
              onChange={(e) =>
                setEditingPlan({
                  ...editingPlan,
                  isRecommended: e.target.checked,
                })
              }
              className="w-5 h-5 rounded text-primary focus:ring-primary border-outline-variant/20"
            />
            <label htmlFor="isRecommended" className="text-sm font-bold text-on-surface">
              Marcar como el Plan Recomendado (Etiqueta destacada)
            </label>
          </div>
          <div className="grid grid-cols-1 md:grid-cols-3 gap-4 pt-4 border-t border-outline-variant/10">
            <div>
              <label className="block text-xs font-bold uppercase tracking-wider text-on-surface-variant mb-2" title="999 para sin límite">
                Límite Reservas / Día
              </label>
              <input
                type="number"
                className="input-field"
                value={editingPlan.limits?.maxBookingsPerDay ?? 1}
                onChange={(e) =>
                  setEditingPlan({
                    ...editingPlan,
                    limits: {
                      ...(editingPlan.limits || {}),
                      maxBookingsPerDay: Number(e.target.value)
                    }
                  })
                }
              />
            </div>
            <div>
              <label className="block text-xs font-bold uppercase tracking-wider text-on-surface-variant mb-2">
                Límite Anuncios / Perfil
              </label>
              <input
                type="number"
                className="input-field"
                value={editingPlan.limits?.maxListingsPerAccount ?? 1}
                onChange={(e) =>
                  setEditingPlan({
                    ...editingPlan,
                    limits: {
                      ...(editingPlan.limits || {}),
                      maxListingsPerAccount: Number(e.target.value)
                    }
                  })
                }
              />
            </div>
            <div>
              <label className="block text-xs font-bold uppercase tracking-wider text-on-surface-variant mb-2">
                Reservas misma franja
              </label>
              <input
                type="number"
                className="input-field"
                value={editingPlan.limits?.maxConcurrentBookings ?? 1}
                onChange={(e) =>
                  setEditingPlan({
                    ...editingPlan,
                    limits: {
                      ...(editingPlan.limits || {}),
                      maxConcurrentBookings: Number(e.target.value)
                    }
                  })
                }
              />
            </div>
          </div>
          <div className="pt-4 border-t border-outline-variant/10">
            <div className="flex justify-between items-center mb-2">
              <label className="block text-xs font-bold uppercase tracking-wider text-on-surface-variant">
                Características / Condiciones
              </label>
              <button
                type="button"
                onClick={handleAddFeature}
                className="text-primary text-xs font-bold hover:underline"
              >
                + Añadir
              </button>
            </div>
            <div className="space-y-2">
              {editingPlan.features.map((f: string, i: number) => (
                <div key={i} className="flex items-center gap-2">
                  <input
                    type="text"
                    className="input-field flex-1"
                    value={f}
                    onChange={(e) => handleFeatureChange(i, e.target.value)}
                  />
                  <button
                    type="button"
                    onClick={() => handleRemoveFeature(i)}
                    className="p-2 text-error hover:bg-error/10 rounded-lg"
                  >
                    <Trash2 className="w-4 h-4" />
                  </button>
                </div>
              ))}
            </div>
          </div>
          <div className="flex justify-end pt-4">
            <button type="submit" className="btn-primary">
              Guardar Cambios
            </button>
          </div>
        </form>
      </div>
    );
  }

  return (
    <div className="bg-surface-container-lowest p-8 rounded-xl shadow-[0_12px_32px_-4px_rgba(44,47,48,0.06)] overflow-hidden">
      <div className="flex justify-between items-center mb-8">
        <div className="flex items-center gap-4">
          <h2 className="text-xl font-bold font-display tracking-tight">
            Planes Pro (Configuración Dinámica)
          </h2>
          <button
            onClick={handleToggleVisibility}
            className={cn(
              "px-4 py-1.5 rounded-full text-xs font-bold transition-colors",
              isEnabled
                ? "bg-green-500/10 text-green-600 hover:bg-green-500/20"
                : "bg-error/10 text-error hover:bg-error/20",
            )}
          >
            {isEnabled
              ? "Ocultar Planes a Usuarios"
              : "Mostrar Planes a Usuarios"}
          </button>
        </div>
        {lastUpdated && (
          <div className="text-xs font-medium text-on-surface-variant/60">
            Contador de usuarios actualizado:{" "}
            {new Date(lastUpdated).toLocaleTimeString()}
          </div>
        )}
      </div>
      <div className="flex flex-col sm:flex-row justify-between items-start sm:items-center gap-4 mb-6">
        <p className="text-sm text-on-surface-variant flex items-center justify-between">
          <span>
            Edita la configuración o comprueba la suscripción a planes. Los
            contadores se actualizan automáticamente cada 3 horas.
          </span>
          {!isEnabled && (
            <span className="text-error font-bold text-xs bg-error/10 px-3 py-1 rounded-full ml-4">
              Los usuarios NO pueden ver u adquirir planes
            </span>
          )}
        </p>

        {/* iPhone Style Toggle */}
        <div className="relative inline-flex bg-surface-container-low p-1 rounded-full">
          <div
            className="absolute top-1 bottom-1 w-1/2 bg-white rounded-full shadow-sm transition-transform duration-300 ease-in-out"
            style={{ transform: isQuarterly ? "translateX(100%)" : "translateX(0)" }}
          />
          <button
            onClick={() => setIsQuarterly(false)}
            className={cn(
              "relative z-10 px-4 py-1.5 text-xs font-bold transition-colors w-24 text-center rounded-full",
              !isQuarterly ? "text-on-surface" : "text-on-surface-variant"
            )}
          >
            Mensual
          </button>
          <button
            onClick={() => setIsQuarterly(true)}
            className={cn(
              "relative z-10 px-4 py-1.5 text-xs font-bold transition-colors w-24 text-center rounded-full",
              isQuarterly ? "text-on-surface" : "text-on-surface-variant"
            )}
          >
            Trimestral
          </button>
        </div>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
        {plans.map((plan) => {
          const subscribersCount = subscriberCounts[plan.id] || 0;
          const displayPrice = isQuarterly ? plan.priceQuarterly : plan.price;
          const displayComparePrice = isQuarterly ? plan.comparePriceQuarterly : plan.comparePrice;

          return (
            <div
              key={plan.id}
              className="p-6 rounded-3xl border border-outline-variant/10 bg-surface flex flex-col items-start gap-4"
            >
              <div className="p-3 bg-primary/10 rounded-2xl text-primary">
                <Crown className="w-6 h-6" />
              </div>
              <div>
                <h5 className="font-display font-black text-lg">{plan.name}</h5>
                <div className="flex items-baseline gap-2 mt-2">
                  <p className="text-2xl font-black">
                    €{displayPrice}
                    <span className="text-sm font-medium text-on-surface-variant/60">
                      {isQuarterly ? "/trimestre" : "/mes"}
                    </span>
                  </p>
                  {displayComparePrice && (
                    <span className="text-sm font-bold text-on-surface-variant/40 line-through">
                      €{displayComparePrice}{isQuarterly ? "/trimestre" : "/mes"}
                    </span>
                  )}
                </div>
              </div>
              <div className="bg-surface-container-low px-3 py-2 rounded-xl text-xs font-bold flex items-center gap-2 border border-outline-variant/10 w-full mb-2">
                <User className="w-3.5 h-3.5 text-primary" /> {subscribersCount}{" "}
                usuarios suscritos
              </div>
              <ul className="space-y-2 mt-2 w-full text-sm flex-1">
                {plan.features.map((f: string, i: number) => (
                  <li key={i} className="flex items-start gap-2 text-left">
                    <Check className="w-4 h-4 text-primary shrink-0 mt-0.5" />
                    <span>{f}</span>
                  </li>
                ))}
              </ul>
              <button
                onClick={() => setEditingPlan(plan)}
                className="w-full py-2 border border-outline-variant hover:bg-surface-container font-bold text-sm rounded-xl mt-4 transition-colors"
              >
                Modificar
              </button>
            </div>
          );
        })}
      </div>
    </div>
  );
};

const AdminLogosConfig = () => {
  const { config, updateConfig } = useDynamicAppConfig();
  const [logo1, setLogo1] = useState(config.logoText1);
  const [logo2, setLogo2] = useState(config.logoText2);
  const [favicon, setFavicon] = useState(config.faviconUrl);
  const [appTitle, setAppTitle] = useState(config.appTitle);
  const [logoImageUrl, setLogoImageUrl] = useState(config.logoImageUrl);
  const [isUploadingFavicon, setIsUploadingFavicon] = useState(false);
  const [isUploadingLogo, setIsUploadingLogo] = useState(false);

  const handleFaviconUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    setIsUploadingFavicon(true);
    try {
      const reader = new FileReader();
      reader.readAsDataURL(file);
      reader.onload = async (event) => {
        const base64 = event.target?.result as string;
        const optimizedUrl = await compressImage(base64, 256, 256);
        setFavicon(optimizedUrl);
        setIsUploadingFavicon(false);
      };
      reader.onerror = () => setIsUploadingFavicon(false);
    } catch (error) {
      console.error(error);
      setIsUploadingFavicon(false);
    }
  };

  const handleLogoUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    setIsUploadingLogo(true);
    try {
      const reader = new FileReader();
      reader.readAsDataURL(file);
      reader.onload = async (event) => {
        const base64 = event.target?.result as string;
        const optimizedUrl = await compressImage(base64, 800, 800);
        setLogoImageUrl(optimizedUrl);
        setIsUploadingLogo(false);
      };
      reader.onerror = () => setIsUploadingLogo(false);
    } catch (error) {
      console.error(error);
      setIsUploadingLogo(false);
    }
  };

  const save = () => {
    updateConfig({ logoText1: logo1, logoText2: logo2, faviconUrl: favicon, appTitle, logoImageUrl });
    const configStr = `Logo 1: "${logo1}"\nLogo 2: "${logo2}"\nFavicon: "${favicon}"\nApp Title: "${appTitle}"\nLogo Image URL: "${logoImageUrl}"`;
    navigator.clipboard.writeText(`Haz fijos estos cambios del logo en el código:\n${configStr}`);
    alert("Cambios guardados localmente en tu navegador.\n\nPara hacerlos permanentes para todos, he copiado los datos a tu portapapeles. ¡Pégalos ahora mismo en el chat de la IA!");
  };

  return (
    <div className="bg-surface-container-lowest p-8 rounded-[2rem] border border-outline-variant/10 space-y-4">
      <h2 className="text-2xl font-black mb-6">Configuración de Logos</h2>
      
      <div>
        <label className="block text-xs font-bold mb-1 text-on-surface-variant">Título de la pestaña del navegador</label>
        <input value={appTitle} onChange={e => setAppTitle(e.target.value)} className="w-full p-4 rounded-xl bg-white border border-outline-variant/20 focus:outline-primary" />
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
        <div>
          <label className="block text-xs font-bold mb-1 text-on-surface-variant">Icono de pestaña (Favicon) - URL o Subir Local</label>
          <input value={favicon} onChange={e => setFavicon(e.target.value)} placeholder="URL..." className="w-full p-4 rounded-xl bg-white border border-outline-variant/20 focus:outline-primary mb-2" />
          <label className="cursor-pointer px-4 py-3 bg-surface-container-low text-primary rounded-xl font-bold inline-block hover:bg-surface-container-high transition-colors">
            {isUploadingFavicon ? "Subiendo..." : "Subir desde PC"}
            <input type="file" accept="image/*" onChange={handleFaviconUpload} className="hidden" disabled={isUploadingFavicon} />
          </label>
          {favicon && (
            <div className="mt-4">
              <img src={favicon} alt="Favicon preview" className="w-16 h-16 object-cover border border-outline-variant rounded-xl" />
            </div>
          )}
        </div>
        
        <div>
          <label className="block text-xs font-bold mb-1 text-on-surface-variant">Logo de la App (Reemplaza los textos si se define)</label>
          <input value={logoImageUrl} onChange={e => setLogoImageUrl(e.target.value)} placeholder="URL..." className="w-full p-4 rounded-xl bg-white border border-outline-variant/20 focus:outline-primary mb-2" />
          <label className="cursor-pointer px-4 py-3 bg-surface-container-low text-primary rounded-xl font-bold inline-block hover:bg-surface-container-high transition-colors">
            {isUploadingLogo ? "Subiendo..." : "Subir desde PC"}
            <input type="file" accept="image/*" onChange={handleLogoUpload} className="hidden" disabled={isUploadingLogo} />
          </label>
          {logoImageUrl && (
            <div className="mt-4">
              <img src={logoImageUrl} alt="Logo preview" className="h-16 w-auto object-contain border border-outline-variant rounded-xl bg-white p-2" />
            </div>
          )}
        </div>
      </div>

      <div className="pt-4 border-t border-outline-variant/10">
        <label className="block text-xs font-bold mb-1 text-on-surface-variant">Nombre App (Parte 1 - Texto alternativo)</label>
        <input value={logo1} onChange={e => setLogo1(e.target.value)} className="w-full p-4 rounded-xl bg-white border border-outline-variant/20 focus:outline-primary" />
      </div>
      <div>
        <label className="block text-xs font-bold mb-1 text-on-surface-variant">Nombre App (Parte 2, resaltada - Texto alternativo)</label>
        <input value={logo2} onChange={e => setLogo2(e.target.value)} className="w-full p-4 rounded-xl bg-white border border-outline-variant/20 focus:outline-primary" />
      </div>

      <button onClick={save} className="px-6 py-3 bg-primary text-white rounded-xl font-bold mt-4">Guardar Logo</button>
    </div>
  );
};

