      const usernameError = validateUsername(user.username);
      if (usernameError) {
        alert(usernameError);
        return;
      }

      const usersRef = collection(db, "users");
      const q = query(usersRef, where("username", "==", user.username));
      const querySnapshot = await getDocs(q);

      // Exclude current user from uniqueness check
      const isTaken =
        !querySnapshot.empty &&
        querySnapshot.docs.some((doc) => doc.id !== user.id);

      if (isTaken) {
        alert("El nombre de usuario ya está ocupado");
        return;
      }

      const userRef = doc(db, "users", user.id);
      const { id, ...dataToUpdate } = user;
      await updateDoc(userRef, { ...dataToUpdate });
      alert("¡Datos guardados correctamente!");
