const RegistrationMapUpdater = ({
  center,
  radius,
}: {
  center: [number, number];
  radius: number;
}) => {
  const map = useMap();
  useEffect(() => {
    if (!map || !center || isNaN(center[0]) || isNaN(center[1])) return;

    try {
      map.invalidateSize();
      if (radius > 0) {
        const lat = center[0];
        const lng = center[1];
        const earthRadius = 6371; // km

        const latDelta = (radius / earthRadius) * (180 / Math.PI);
        const lngDelta =
          (radius / (earthRadius * Math.cos((lat * Math.PI) / 180))) *
          (180 / Math.PI);

        const bounds = L.latLngBounds(
          [lat - latDelta, lng - lngDelta],
          [lat + latDelta, lng + lngDelta],
        );

        if (bounds.isValid()) {
          map.fitBounds(bounds, { padding: [40, 40], animate: true });
        }
      } else {
        map.setView(center, 15, { animate: true });
      }
    } catch (err) {
      console.error("Map focus error:", err);
    }
  }, [center[0], center[1], radius, map]);
  return null;
};

const WorkZoneMap = ({
  center,
  radius,
}: {
  center: [number, number];
  radius: number;
}) => {
  return (
    <div className="h-64 sm:h-80 w-full rounded-[2rem] overflow-hidden border border-outline-variant relative z-10">
      <MapContainer
        center={center}
        zoom={13}
        scrollWheelZoom={false}
        className="h-full w-full"
      >
        <TileLayer
          attribution='&copy; <a href="https://www.openstreetmap.org/copyright">OpenStreetMap</a> contributors'
          url="https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png"
        />
        <Circle
          center={center}
          radius={radius * 1000}
          pathOptions={{
            color: "#00675b",
            fillColor: "#00675b",
            fillOpacity: 0.1,
            weight: 2,
          }}
        />
        <Marker position={center} />
        <RegistrationMapUpdater center={center} radius={radius} />
      </MapContainer>
    </div>
  );
};

