  // Geocoding effect for availability settings
  useEffect(() => {
    if (
      generalTab === "availability" &&
      user?.professionalInfo?.workLocation &&
      user.professionalInfo.workLocation.length > 3
    ) {
      const timeoutId = setTimeout(async () => {
        try {
          const response = await fetch(
            `https://nominatim.openstreetmap.org/search?format=json&q=${encodeURIComponent(user.professionalInfo!.workLocation)}&limit=1`,
          );
          const data = await response.json();
          if (data && data[0]) {
            const coords: [number, number] = [
              parseFloat(data[0].lat),
              parseFloat(data[0].lon),
            ];
            if (
              user.professionalInfo?.workCoords?.[0] !== coords[0] ||
              user.professionalInfo?.workCoords?.[1] !== coords[1]
            ) {
              setUser({
                ...user,
                professionalInfo: {
                  ...user.professionalInfo!,
                  workCoords: coords,
                },
              });
            }
          }
        } catch (err) {
          console.error("Settings geocoding error:", err);
        }
      }, 1000);
      return () => clearTimeout(timeoutId);
    }
  }, [user?.professionalInfo?.workLocation, generalTab]);

