                className="flex items-center gap-2 bg-primary text-white px-4 sm:px-6 py-2.5 sm:py-3 rounded-full font-black text-[9px] sm:text-[10px] uppercase tracking-widest hover:scale-105 transition-all shadow-lg ml-2"
              >
                <PlusCircle className="w-4 h-4" />
