                  className="w-full pl-10 pr-4 py-3.5 sm:py-3 bg-surface-container-low border-none rounded-xl font-bold text-[10px] uppercase tracking-widest text-on-surface-variant outline-none focus:ring-2 focus:ring-primary/10 transition-all placeholder:text-on-surface-variant/20"
