const RichTextEditor = ({
  value,
  onChange,
  placeholder,
  minHeight = "100px",
}: {
  value: string;
  onChange: (html: string) => void;
  placeholder?: string;
  minHeight?: string;
}) => {
  const editorRef = useRef<HTMLDivElement>(null);
  const savedRange = useRef<Range | null>(null);
  const initialized = useRef(false);

  useEffect(() => {
    if (editorRef.current && !initialized.current) {
      editorRef.current.innerHTML = value || "";
      initialized.current = true;
    }
  }, [value]);

  const saveSelection = () => {
    const sel = window.getSelection();
    if (sel && sel.rangeCount > 0 && editorRef.current?.contains(sel.anchorNode)) {
      savedRange.current = sel.getRangeAt(0);
    }
  };

  const restoreSelection = () => {
    if (!savedRange.current) return;
    const sel = window.getSelection();
    if (sel) {
      sel.removeAllRanges();
      sel.addRange(savedRange.current);
    }
  };

  const exec = (cmd: string, val?: string) => {
    editorRef.current?.focus();
    restoreSelection();
    document.execCommand(cmd, false, val);
    onChange(editorRef.current?.innerHTML || "");
  };

  const applyFontSize = (px: string) => {
    editorRef.current?.focus();
    restoreSelection();

    const sel = window.getSelection();
    if (!sel || !sel.rangeCount || sel.isCollapsed) {
      onChange(editorRef.current?.innerHTML || "");
      return;
    }

    const range = sel.getRangeAt(0);
    const span = document.createElement("span");
    span.style.setProperty("font-size", px, "important");
    try {
      range.surroundContents(span);
    } catch {
      const fragment = range.extractContents();
      span.appendChild(fragment);
      range.insertNode(span);
    }
    sel.removeAllRanges();
    const newRange = document.createRange();
    newRange.selectNodeContents(span);
    sel.addRange(newRange);
    onChange(editorRef.current?.innerHTML || "");
  };

  return (
    <div className="border border-outline-variant/20 rounded-xl overflow-hidden">
      <div className="flex items-center gap-1 p-1.5 bg-surface-container border-b border-outline-variant/20 flex-wrap">
        <button
          type="button"
          onMouseDown={(e) => { e.preventDefault(); exec("bold"); }}
          className="w-8 h-8 flex items-center justify-center rounded-lg hover:bg-surface-container-high font-black text-sm"
          title="Negrita"
        >
          <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round"><path d="M14 12a4 4 0 0 0 0-8H6v8"/><path d="M15 20a4 4 0 0 0 0-8H6v8"/></svg>
        </button>
        <button
          type="button"
          onMouseDown={(e) => { e.preventDefault(); exec("italic"); }}
          className="w-8 h-8 flex items-center justify-center rounded-lg hover:bg-surface-container-high italic text-sm"
          title="Cursiva"
        >
          <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round"><line x1="19" x2="10" y1="4" y2="4"/><line x1="14" x2="5" y1="20" y2="20"/><line x1="15" x2="9" y1="4" y2="20"/></svg>
        </button>
        <button
          type="button"
          onMouseDown={(e) => { e.preventDefault(); exec("underline"); }}
          className="w-8 h-8 flex items-center justify-center rounded-lg hover:bg-surface-container-high underline text-sm"
          title="Subrayado"
        >
          <svg width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round"><path d="M6 4v6a6 6 0 0 0 12 0V4"/><line x1="4" x2="20" y1="20" y2="20"/></svg>
        </button>
        <div className="w-px h-6 bg-outline-variant/20 mx-1" />
        <select
          onChange={(e) => {
            const val = e.target.value;
            if (val) applyFontSize(val);
            e.target.value = "";
          }}
          className="text-xs bg-surface-container-high rounded-lg px-2 py-1 border border-outline-variant/10 outline-none cursor-pointer"
        >
          <option value="">Tamaño</option>
          <option value="14px">Pequeño</option>
          <option value="16px">Normal</option>
          <option value="20px">Grande</option>
          <option value="24px">Muy Grande</option>
          <option value="32px">Extra Grande</option>
        </select>
      </div>
      <div
        ref={editorRef}
        contentEditable
        suppressContentEditableWarning
        onInput={() => {
          onChange(editorRef.current?.innerHTML || "");
        }}
        onMouseUp={saveSelection}
        onKeyUp={saveSelection}
        className="p-3 outline-none text-sm leading-relaxed empty:before:content-[attr(data-placeholder)] empty:before:text-on-surface-variant/40"
        data-placeholder={placeholder || ""}
        style={{ minHeight }}
      />
    </div>
  );
};

const ScrollToTop = () => {
  const { pathname } = useLocation();
  useEffect(() => {
    window.scrollTo(0, 0);
  }, [pathname]);
  return null;
};

const EmailVerificationScreen = ({ user, auth, isModal, setUser }: { user: UserProfile, auth: any, isModal?: boolean, setUser?: any }) => {
  const [isSending, setIsSending] = useState(false);
  const [message, setMessage] = useState("");

  const navigate = useNavigate();

  const handleResend = async () => {
    if (!auth.currentUser) return;
    setIsSending(true);
    try {
      auth.languageCode = navigator.language || 'es';
      await sendEmailVerification(auth.currentUser);
      setMessage("Se ha enviado un nuevo enlace de verificación a tu correo.");
    } catch (error: any) {
      console.error(error);
      if (error.code === 'auth/too-many-requests') {
        setMessage("Has intentado reenviar el correo demasiadas veces. Por favor, espera unos minutos.");
      } else {
        setMessage("Hubo un error al enviar el correo. Por favor, inténtalo más tarde.");
      }
    }
    setIsSending(false);
  };

  const handleCheck = async () => {
    if (!auth.currentUser) return;
    await auth.currentUser.reload();
    if (auth.currentUser.emailVerified) {
      window.location.reload();
    } else {
      setMessage("Todavía no se ha verificado el correo. Revisa tu bandeja de entrada o spam.");
    }
  };

  const handleLogout = async () => {
    if (setUser) setUser(null);
    await auth.signOut();
    navigate("/");
  };

  return (
    <div className={isModal ? "fixed inset-0 z-[9999] bg-black/60 backdrop-blur-sm flex items-center justify-center p-4 text-center" : "min-h-screen bg-surface flex flex-col items-center justify-center p-4 text-center"}>
      <div className="bg-surface-container-lowest rounded-[3rem] p-8 max-w-md w-full shadow-xl pointer-events-auto">
        <h2 className="text-2xl font-black mb-4">Verifica tu correo electrónico</h2>
        <p className="text-on-surface-variant mb-8 text-sm">
          Hemos enviado un enlace de verificación a <br/><strong>{auth.currentUser?.email}</strong>.<br/><br/>
          Por favor, haz clic en el enlace para activar tu cuenta y poder utilizar la plataforma.
        </p>
        
        {message && (
          <div className="bg-primary/10 text-primary p-3 rounded-xl mb-6 text-sm font-medium">
            {message}
          </div>
        )}

        <div className="space-y-3">
          <button
            onClick={handleCheck}
            className="w-full bg-primary text-white py-4 rounded-xl font-bold shadow-lg"
          >
            Ya he verificado mi correo
          </button>
          
          <button
            onClick={handleResend}
            disabled={isSending}
            className="w-full border-2 border-primary/20 text-primary py-4 rounded-xl font-bold hover:bg-primary/5 transition-colors"
          >
            {isSending ? "Enviando..." : "Reenviar correo"}
          </button>

          <button
            onClick={handleLogout}
            className="w-full text-on-surface-variant mt-4 text-sm font-medium hover:text-on-surface transition-colors"
          >
            Cerrar sesión
          </button>
        </div>
      </div>
    </div>
  );
};

function App() {
  const location = useLocation();
  const navigate = useNavigate();
  const [searchParams, setSearchParams] = useSearchParams();
  const [isMenuOpen, setIsMenuOpen] = useState(false);
  const [isCalendarModalOpen, setIsCalendarModalOpen] = useState(false);
  const [search, setSearch] = useState("");

  const [reportTarget, setReportTarget] = useState<{
    userId: string;
    listingId?: string;
    conversationId?: string;
  } | null>(null);

  const handleReportUserAction = async (reason: string, details: string) => {
    if (!reportTarget || !auth.currentUser?.uid) return;

    try {
      await addDoc(collection(db, "reports"), {
        reportedUserId: reportTarget.userId,
        reporterUserId: auth.currentUser.uid,
        listingId: reportTarget.listingId || null,
        conversationId: reportTarget.conversationId || null,
        reason: reason,
        description: details,
        isRead: false,
        status: "pending",
        createdAt: serverTimestamp(),
      });
      alert(
        "Reporte enviado correctamente. Revisaremos el caso lo antes posible.",
      );
    } catch (e) {
      console.error("Error reporting user:", e);
      alert("Error al enviar el reporte. Inténtalo de nuevo más tarde.");
    }
  };

  const [user, setUser] = useState<UserProfile | null>(() => {
    try {
      const saved = localStorage.getItem("jobpop_user");
      if (!saved) return null;
      const parsed = JSON.parse(saved);
      if (
        parsed &&
        typeof parsed === "object" &&
        parsed.email &&
        (parsed.name || parsed.username || parsed.firstName)
      ) {
        return parsed;
      }
      // If data is invalid, clear it to prevent further crashes
      localStorage.removeItem("jobpop_user");
      return null;
    } catch (e) {
      console.error("Error loading user from localStorage:", e);
      localStorage.removeItem("jobpop_user");
      return null;
    }
  });

  useEffect(() => {
    if (user && !user.customId) {
      setUser((prev) =>
        prev
          ? { ...prev, customId: generateCustomId(prev.firstName, new Date()) }
          : null,
      );
    }
  }, [user]);

  const [settingsModal, setSettingsModal] = useState<{
    isOpen: boolean;
    type: string;
  }>({ isOpen: false, type: "" });

  // Global seed for testing requested user
  useEffect(() => {
    const seed = async () => {
      try {
        await createUserWithEmailAndPassword(
          auth,
          "paco@paco.com",
          "12-mayo-D",
        );
        console.log("Seed: Created paco@paco.com");
      } catch (e: any) {
        if (e.code !== "auth/email-already-in-use") {
          console.log("Seed check:", e.code);
        }
      }
    };
    seed();
  }, []);

  // Handle Stripe Checkout success
  useEffect(() => {
    if (user && searchParams.get("checkout") === "success") {
      const planId = searchParams.get("plan_id");
      if (planId && user.professionalInfo?.plan !== planId) {
        const updatePlanAsync = async () => {
          try {
            const now = new Date();
            const cycle = "monthly";
            const endDate = new Date(now);
            endDate.setMonth(endDate.getMonth() + 1);

            const updatedUser = {
              ...user,
              professionalInfo: {
                ...(user?.professionalInfo || {
                  billing: {},
                  availability: [],
                  workLocation: "",
                }),
                plan: planId,
                planStartDate: now.toISOString().split("T")[0],
                planEndDate: endDate.toISOString().split("T")[0],
                planStatus: "active",
                planBillingCycle: cycle,
                planAutoRenew: true,
              },
            } as UserProfile;

            const { id, ...dataToUpdate } = updatedUser;
            await updateDoc(doc(db, "users", user.id), { ...dataToUpdate });
            setUser(updatedUser);
            alert("¡Pago exitoso! Tu plan ha sido actualizado.");
          } catch(e) {
            console.error("Error updating plan after payment:", e);
          } finally {
             const params = new URLSearchParams(searchParams);
             params.delete("checkout");
             params.delete("plan_id");
             setSearchParams(params);
          }
        };
        updatePlanAsync();
      } else {
         const params = new URLSearchParams(searchParams);
         params.delete("checkout");
         params.delete("plan_id");
         setSearchParams(params);
      }
    } else if (searchParams.get("checkout") === "canceled") {
      alert("El pago ha sido cancelado.");
      const params = new URLSearchParams(searchParams);
      params.delete("checkout");
      setSearchParams(params);
    }
  }, [user, searchParams, setSearchParams]);

  // Ensure Firebase Auth is initialized and sync with user state
  useEffect(() => {
    let unsubsDoc: (() => void) | undefined;
    
    const unsubAuth = onAuthStateChanged(auth, async (firebaseUser) => {
      if (firebaseUser) {
        console.log("Firebase: Authenticated as", firebaseUser.uid);
        if (user && user.id !== firebaseUser.uid) {
          console.log("Syncing user ID with Firebase UID");
          setUser((prev) => (prev ? { ...prev, id: firebaseUser.uid } : null));
        }

        unsubsDoc = onSnapshot(doc(db, "users", firebaseUser.uid), (docSnap) => {
          if (docSnap.exists()) {
            const data = docSnap.data();
            if (firebaseUser.emailVerified && data.emailVerified !== true) {
              import("firebase/firestore").then(({ updateDoc }) => {
                updateDoc(doc(db, "users", firebaseUser.uid), { emailVerified: true }).catch(console.error);
              });
            }
            const remoteUser = { id: firebaseUser.uid, email: firebaseUser.email || undefined, ...data } as UserProfile;
             // Update the global state so admin edits reflect immediately 
             // without the user needing to refresh
            setUser(prev => {
              if (JSON.stringify(prev) !== JSON.stringify(remoteUser)) {
                return remoteUser;
              }
              return prev;
            });
          }
        });
      } else {
        console.log("Firebase: No user authenticated");
        if (unsubsDoc) {
           unsubsDoc();
           unsubsDoc = undefined;
        }
      }
    });

    return () => {
      unsubAuth();
      if (unsubsDoc) {
        unsubsDoc();
      }
    };
  }, []);

  // Presence tracking in real-time
  useEffect(() => {
    let activeInterval: NodeJS.Timeout;
    const updatePresence = async () => {
      if (user?.id && auth.currentUser) {
        try {
          await setDoc(doc(db, "users", user.id), {
            lastActive: serverTimestamp()
          }, { merge: true });
        } catch (e) {
          // Ignore failed presence updates
        }
      }
    };
    updatePresence();
    activeInterval = setInterval(updatePresence, 5000);
    return () => {
      if (activeInterval) clearInterval(activeInterval);
    };
  }, [user?.id]);

  const [listings, setListings] = useState<JobListing[]>(() => {
    try {
      const saved = localStorage.getItem("jobpop_listings");
      if (saved === null) return INITIAL_LISTINGS;
      const parsed = JSON.parse(saved);
      if (Array.isArray(parsed)) {
        // Filter out malformed listings instead of resetting everything
        const validListings = parsed.filter(
          (l) =>
            l &&
            typeof l === "object" &&
            typeof l.id === "string" &&
            typeof l.title === "string" &&
            l.author &&
            typeof l.author === "object" &&
            typeof l.author.name === "string" &&
            l.author.name.trim() !== "",
        );
        return validListings.length > 0 ? validListings : INITIAL_LISTINGS;
      }
      return INITIAL_LISTINGS;
    } catch (e) {
      console.error("Error loading listings from localStorage:", e);
      return INITIAL_LISTINGS;
    }
  });

  useEffect(() => {
    const unsubListings = onSnapshot(collection(db, "listings"), (snapshot) => {
      const fbListings = snapshot.docs.map(
        (doc) => ({ id: doc.id, ...doc.data() } as JobListing)
      );
      setListings(fbListings);
    }, (err) => {
      console.error("Error syncing listings:", err);
    });
    return () => unsubListings();
  }, []);

  const [favorites, setFavorites] = useState<string[]>(() => {
    try {
      const saved = localStorage.getItem("jobpop_favorites");
      return saved ? JSON.parse(saved) : [];
    } catch (e) {
      return [];
    }
  });

  const [unreadMessagesCount, setUnreadMessagesCount] = useState(0);

  const [footerConfig, setFooterConfig] = useState<FooterConfig>(
    DEFAULT_FOOTER_CONFIG,
  );

  useEffect(() => {
    const unsub = onSnapshot(doc(db, "settings", "footer"), async (docSnap) => {
      if (docSnap.exists() && docSnap.data().columns) {
        let config = docSnap.data() as FooterConfig;

        // Auto-migrate to add Blog if missing
        const hasBlog = config.columns.some((c) =>
          c.links.some((l) => l.url === "/blog"),
        );
        if (!hasBlog && config.columns[0]) {
          config.columns[0].links.push({ label: "Blog", url: "/blog" });
        }

        setFooterConfig(config);
      } else {
        setFooterConfig(DEFAULT_FOOTER_CONFIG);
      }
    });
    return () => unsub();
  }, []);

  useEffect(() => {
    const handleAdminUserUpdate = (e: any) => {
      const editedUser = e.detail;
      setListings((prev) =>
        prev.map((l) => {
          if (
            l.author &&
            (l.author.id === editedUser.id ||
              l.author.email === editedUser.email)
          ) {
            return {
              ...l,
              author: {
                ...l.author,
                isVerified: editedUser.isVerified === true,
              },
            };
          }
          return l;
        }),
      );
      if (
        user &&
        (user.id === editedUser.id || user.email === editedUser.email)
      ) {
        setUser((prev) =>
          prev ? { ...prev, ...editedUser } : null,
        );
      }
    };
    window.addEventListener("admin-updated-user", handleAdminUserUpdate);
    return () =>
      window.removeEventListener("admin-updated-user", handleAdminUserUpdate);
  }, [user]);

  useEffect(() => {
    let unsubscribe: (() => void) | undefined;
    const unsubAuth = onAuthStateChanged(auth, (firebaseUser) => {
      if (unsubscribe) {
        unsubscribe();
        unsubscribe = undefined;
      }

      if (!firebaseUser) {
        setUnreadMessagesCount(0);
        return;
      }

      const q = query(
        collection(db, "conversations"),
        where("participants", "array-contains", firebaseUser.uid),
      );

      unsubscribe = onSnapshot(
        q,
        (snapshot) => {
          let count = 0;
          snapshot.docs.forEach((doc) => {
            const data = doc.data();
            if (data.unreadCount && data.unreadCount[firebaseUser.uid]) {
              count += data.unreadCount[firebaseUser.uid];
            }
          });
          setUnreadMessagesCount(count);
        },
        (error) => {
          console.error("Navbar [conversations unread]: Error:", error);
        },
      );
    });

    return () => {
      unsubAuth();
      if (unsubscribe) {
        unsubscribe();
      }
    };
  }, []);

  const [notifications, setNotifications] = useState<
    { id: string; title: string; time: string; read: boolean }[]
  >([
    {
      id: "1",
      title: "Nuevo mensaje de María García",
      time: "Hace 5 min",
      read: false,
    },
    {
      id: "2",
      title: "Tu anuncio ha sido verificado",
      time: "Hace 2 horas",
      read: true,
    },
    {
      id: "3",
      title: "Alguien guardó tu anuncio en favoritos",
      time: "Hace 1 día",
      read: true,
    },
  ]);

  const [activeToast, setActiveToast] = useState<{
    message: string;
    type: "message" | "alert";
  } | null>(null);

  const [globalPopupsConfig, setGlobalPopupsConfig] = useState<Record<string, any>>({});
  
  const getActivePopupConfig = () => {
    if (!globalPopupsConfig) return null;
    
    if (user && sessionStorage.getItem("is_first_login_session") === "true") {
      if (globalPopupsConfig.first_login?.active) return globalPopupsConfig.first_login;
    }
    if (!user) {
      if (globalPopupsConfig.guests?.active) return globalPopupsConfig.guests;
    }
    if (globalPopupsConfig.all?.active) return globalPopupsConfig.all;
    
    return null;
  };

  const globalPopupConfig = getActivePopupConfig();

  const [isPopupOpen, setIsPopupOpen] = useState(false);
  const [popupEmail, setPopupEmail] = useState("");
  const [isSubmittingPopup, setIsSubmittingPopup] = useState(false);

  const handlePopupSubmit = async () => {
    if (globalPopupConfig?.showEmailInput && !popupEmail) {
      alert("Por favor introduce tu correo electrónico.");
      return;
    }

    if (globalPopupConfig?.showEmailInput && popupEmail) {
      setIsSubmittingPopup(true);
      try {
        await addDoc(collection(db, "popupLeads"), {
          email: popupEmail,
          name: user
            ? [user.firstName, user.lastName1, user.lastName2]
                .filter(Boolean)
                .join(" ") ||
              user.username ||
              "Usuario Anónimo"
            : "Usuario Anónimo",
          userId: user?.id || null,
          createdAt: serverTimestamp(),
        });
      } catch (e) {
        console.error(e);
      } finally {
        setIsSubmittingPopup(false);
      }
    }

    if (globalPopupConfig?.buttonRedirectToRegister) {
      navigate("/registro", { state: { fromPopup: true } });
    } else if (globalPopupConfig?.redirectGuestsToRegister && !user) {
      navigate("/registro");
    } else if (globalPopupConfig?.buttonUrl) {
      window.open(globalPopupConfig.buttonUrl, "_blank");
    }
    setIsPopupOpen(false);
  };

  useEffect(() => {
    const unsub = onSnapshot(doc(db, "settings", "popups"), (docSnap) => {
      if (docSnap.exists()) {
        setGlobalPopupsConfig(docSnap.data());
      } else {
        getDocFromServer(doc(db, "settings", "popup")).then((oldSnap) => {
          if (oldSnap.exists()) {
            const data = oldSnap.data();
            setGlobalPopupsConfig({ [data.targetAudience || "all"]: data });
          } else {
            setIsPopupOpen(false);
          }
        });
      }
    });
    return () => unsub();
  }, []);

  useEffect(() => {
    let delayTimer: NodeJS.Timeout;

    const shouldShow =
      globalPopupConfig &&
      globalPopupConfig.active &&
      !sessionStorage.getItem("popup_seen") &&
      location.pathname === "/";

    const handleScroll = () => {
      if (shouldShow && globalPopupConfig?.triggerType === "scroll") {
        const scrollHeight =
          document.documentElement.scrollHeight - window.innerHeight;
        const scrollPercent =
          scrollHeight > 0 ? (window.scrollY / scrollHeight) * 100 : 0;
        const targetPercent = globalPopupConfig.triggerScrollPercentage || 50;
        if (scrollPercent >= targetPercent) {
          setIsPopupOpen(true);
          sessionStorage.setItem("popup_seen", "true");
          window.removeEventListener("scroll", handleScroll);
        }
      }
    };

    const handleMouseLeave = (e: MouseEvent) => {
      if (shouldShow && globalPopupConfig?.triggerType === "exit") {
        if (e.clientY <= 0) {
          setIsPopupOpen(true);
          sessionStorage.setItem("popup_seen", "true");
          document.removeEventListener("mouseleave", handleMouseLeave);
        }
      }
    };

    if (shouldShow) {
      const type = globalPopupConfig.triggerType || "delay";

      if (type === "delay") {
        const delayMs =
          globalPopupConfig.delaySeconds !== undefined
            ? globalPopupConfig.delaySeconds * 1000
            : 1500;
        delayTimer = setTimeout(() => {
          setIsPopupOpen(true);
          sessionStorage.setItem("popup_seen", "true");
        }, delayMs);
      } else if (type === "scroll") {
        window.addEventListener("scroll", handleScroll);
        // Check immediately in case page is short or already scrolled
        handleScroll();
      } else if (type === "exit") {
        document.addEventListener("mouseleave", handleMouseLeave);
      }
    }

    return () => {
      clearTimeout(delayTimer);
      window.removeEventListener("scroll", handleScroll);
      document.removeEventListener("mouseleave", handleMouseLeave);
    };
  }, [globalPopupConfig, user, location.pathname]);

  const socketRef = useRef<Socket | null>(null);

  useEffect(() => {
    // Connect to socket
    let socket: any;
    try {
      socket = io();
      socketRef.current = socket;

      if (user?.email) {
        socket.emit("join", user.email);
      }

      socket.on("new_message", (data: any) => {
        if (!data || !data.senderName) return;
        setNotifications((prev: any) => [
          {
            id: Date.now().toString(),
            title: `Nuevo mensaje de ${data.senderName}`,
            time: "Ahora mismo",
            read: false,
          },
          ...prev,
        ]);
        setActiveToast({
          message: `${data.senderName}: ${data.text || ""}`,
          type: "message",
        });
      });

      socket.on("job_alert", (data: any) => {
        if (!data || !data.title) return;
        setNotifications((prev: any) => [
          {
            id: Date.now().toString(),
            title: `Nueva alerta: ${data.title} en ${data.location || "tu zona"}`,
            time: "Ahora mismo",
            read: false,
          },
          ...prev,
        ]);
        setActiveToast({
          message: `${data.title} en ${data.location || "tu zona"}`,
          type: "alert",
        });
      });
    } catch (err) {
      console.error("Socket connection error:", err);
    }

    return () => {
      if (socket) socket.disconnect();
    };
  }, [user?.email]);

  useEffect(() => {
    if (activeToast) {
      const timer = setTimeout(() => setActiveToast(null), 5000);
      return () => clearTimeout(timer);
    }
  }, [activeToast]);

  useEffect(() => {
    localStorage.setItem("jobpop_listings", JSON.stringify(listings));
    console.log("Current listings count:", listings.length);
  }, [listings]);

  useEffect(() => {
    localStorage.setItem("jobpop_favorites", JSON.stringify(favorites));
  }, [favorites]);

  useEffect(() => {
    if (user) {
      localStorage.setItem("jobpop_user", JSON.stringify(user));

      // Sync user data with their listings
      setListings((prev) => {
        if (!Array.isArray(prev)) return prev;
        const displayName =
          user.username || `${user.firstName} ${user.lastName1}`;
        return prev.map((l) => {
          if (
            l &&
            l.author &&
            (l.author.id === user.id || l.author.email === user.email)
          ) {
            const isOffer = l.type === "offer";
            return {
              ...l,
              location: isOffer
                ? user.professionalInfo?.workLocation || l.location
                : l.location,
              coordinates: isOffer
                ? user.professionalInfo?.workCoords
                  ? {
                      lat: user.professionalInfo.workCoords[0],
                      lng: user.professionalInfo.workCoords[1],
                    }
                  : l.coordinates
                : l.coordinates,
              travelDistance: isOffer
                ? user.professionalInfo?.workRadius || l.travelDistance
                : l.travelDistance,
              availability: isOffer
                ? user.professionalInfo?.availability || l.availability
                : l.availability,
              author: {
                ...l.author,
                id: user.id,
                name: displayName,
                photoUrl: user.photoUrl,
                isVerified: user.isVerified === true,
                certifications: user.certifications,
                gallery: user.gallery,
              },
            };
          }
          return l;
        });
      });
    } else {
      localStorage.removeItem("jobpop_user");
    }
  }, [user]);

  const toggleFavorite = (id: string) => {
    setFavorites((prev) =>
      prev.includes(id) ? prev.filter((favId) => favId !== id) : [...prev, id],
    );
  };

  const addListing = async (newListing: JobListing) => {
    try {
      if (!newListing || !newListing.id || !newListing.author) {
        throw new Error("Anuncio malformado: faltan campos obligatorios.");
      }

      // Ensure coordinates are valid if present
      if (
        newListing.coordinates &&
        (isNaN(newListing.coordinates.lat) || isNaN(newListing.coordinates.lng))
      ) {
        console.warn(
          "Invalid coordinates detected, removing them to prevent map crashes",
        );
        delete newListing.coordinates;
      }

      console.log("Adding new listing to state:", newListing);
      await setDoc(doc(db, "listings", newListing.id), newListing);

      setListings((prev) => {
        if (!Array.isArray(prev)) return [newListing];
        return [newListing, ...prev];
      });
    } catch (e) {
      console.error("Error adding listing:", e);
      // We don't have a global setError in App, so we re-throw to be caught by CreateListing
      throw e;
    }
  };

  const reactivateListing = async (id: string) => {
    const creationDate = new Date();
    const expirationDate = new Date(
      creationDate.getTime() + 30 * 24 * 60 * 60 * 1000,
    ); // 30 days

    try {
      await updateDoc(doc(db, "listings", id), {
        status: "active",
        expiresAt: expirationDate.toISOString(),
      });
    } catch (e) {
      console.error("Error reactivating listing in Firebase", e);
    }

    setListings((prev) =>
      prev.map((l) => {
        if (l.id === id) {
          return {
            ...l,
            status: "active",
            expiresAt: expirationDate.toISOString(),
          };
        }
        return l;
      }),
    );
    setActiveToast({
      message: "Anuncio reactivado por 30 días.",
      type: "message",
    });
  };

  const simulateNotification = (type: "message" | "alert") => {
    if (type === "message") {
      socketRef.current?.emit("send_message", {
        to: user?.email,
        from: "system@jobpop.com",
        senderName: "Sistema JobPop",
        text: "¡Bienvenido! Tu cuenta ha sido configurada correctamente.",
      });
    } else {
      socketRef.current?.emit("broadcast_job_alert", {
        title: "Nuevo trabajo de Limpieza",
        category: "Hogar",
        location: "Madrid Centro",
      });
    }
  };

  const isDashboard =
    location.pathname.startsWith("/mensajes") ||
    location.pathname.startsWith("/mis-anuncios") ||
    location.pathname.startsWith("/favoritos") ||
    location.pathname.startsWith("/estadisticas") ||
    location.pathname.startsWith("/monederos") ||
    location.pathname.startsWith("/configuracion");

  const isEmailVerified = user && auth.currentUser ? auth.currentUser.emailVerified || user.role === "admin" : true;

  return (
    <ReportContext.Provider
      value={{
        openReportModal: (userId, listingId, conversationId) =>
          setReportTarget({ userId, listingId, conversationId }),
      }}
    >
      {user && auth.currentUser && !isEmailVerified && (
        <EmailVerificationScreen user={user} auth={auth} isModal={true} setUser={setUser} />
      )}
      <div
        className={cn(
          "font-sans text-gray-900 antialiased selection:bg-blue-100 selection:text-blue-900",
          isDashboard && "h-screen overflow-hidden flex flex-col",
        )}
      >
        <ScrollToTop />
        <SettingsModal
          isOpen={settingsModal.isOpen}
          onClose={() => setSettingsModal({ ...settingsModal, isOpen: false })}
          type={settingsModal.type}
          user={user}
          setUser={setUser}
          onSimulateNotification={simulateNotification}
        />
        <ReportModal
          isOpen={!!reportTarget}
          onClose={() => setReportTarget(null)}
          onSubmit={handleReportUserAction}
        />
        <Navbar
          user={user}
          setUser={setUser}
          favoritesCount={favorites.length}
          notifications={notifications}
          setNotifications={setNotifications}
          onOpenSettings={(type) => setSettingsModal({ isOpen: true, type })}
          unreadMessagesCount={unreadMessagesCount}
          isMenuOpen={isMenuOpen}
          setIsMenuOpen={setIsMenuOpen}
          search={search}
          setSearch={setSearch}
          onOpenCalendarModal={() => setIsCalendarModalOpen(true)}
        />
        <AnimatePresence>
          {isMenuOpen && (
            <motion.div
              key="mobile-menu-dropdown"
              initial={{ opacity: 0, y: -10 }}
              animate={{ opacity: 1, y: 0 }}
              exit={{ opacity: 0, y: -10 }}
              transition={{ type: "spring", damping: 25, stiffness: 300 }}
              className="fixed top-0 left-0 right-0 bottom-16 z-[50] bg-white flex flex-col shadow-2xl overflow-hidden"
            >
              <div className="flex items-center justify-between px-6 h-16 border-b border-outline-variant shrink-0">
                <span className="font-display font-black text-on-surface uppercase tracking-widest text-xs">
                  Área personal
                </span>
                <button
                  onClick={() => setIsMenuOpen(false)}
                  className="w-10 h-10 rounded-full bg-surface-container-low flex items-center justify-center text-on-surface-variant"
                >
                  <X className="w-5 h-5" />
                </button>
              </div>
              <div className="overflow-y-auto no-scrollbar px-6 py-8 space-y-8 pb-12 flex-1">
                {/* General Navigation */}
                <div className="space-y-4">
                  <div className="text-[10px] font-black text-on-surface-variant/30 uppercase tracking-[0.3em] px-2 flex items-center gap-4">
                    <span>Descubrir</span>
                    <div className="h-[1px] flex-1 bg-outline-variant/10"></div>
                  </div>
                </div>

                {/* Profile Section for logged in users */}
                {user && (
                  <div className="bg-surface-container-low rounded-[2rem] p-6 flex items-center gap-4 border border-outline-variant/10">
                    {user.photoUrl ? (
                      <img
                        src={user.photoUrl}
                        alt={user.username}
                        className="w-16 h-16 rounded-full object-cover border-2 border-white shadow-sm"
                        referrerPolicy="no-referrer"
                      />
                    ) : (
                      <div className="w-16 h-16 rounded-full primary-gradient flex items-center justify-center text-white font-bold text-xl shadow-sm">
                        {(user.username || user.firstName || "?").charAt(0)}
                      </div>
                    )}
                    <div className="flex-1 min-w-0">
                      <div className="font-display font-black text-on-surface truncate">
                        {user.username || user.firstName}
                      </div>
                      <div className="text-[10px] text-on-surface-variant/40 uppercase tracking-widest font-bold truncate">
                        {user.email}
                      </div>
                      <Link
                        to="/perfil"
                        onClick={() => setIsMenuOpen(false)}
                        className="inline-block mt-2 text-[9px] font-black uppercase tracking-widest text-primary hover:underline"
                      >
                        Ver perfil público
                      </Link>
                    </div>
                  </div>
                )}

                <div className="space-y-6">
                  <div className="text-[10px] font-black text-on-surface-variant/30 uppercase tracking-[0.3em] px-2 flex items-center gap-4">
                    <span>Tu Gestión</span>
                    <div className="h-[1px] flex-1 bg-outline-variant/10"></div>
                  </div>
                  {user ? (
                    <div className="grid grid-cols-1 gap-3">
                      <div className="flex flex-col gap-3">
                        <Link
                          to="/favoritos"
                          onClick={() => setIsMenuOpen(false)}
                          className="flex items-center gap-4 p-4 bg-surface-container-low rounded-2xl text-on-surface hover:bg-primary/5 hover:text-primary transition-all border border-outline-variant/10 group"
                        >
                          <div className="w-10 h-10 bg-white rounded-xl shadow-inner flex items-center justify-center relative">
                            <Heart className="w-5 h-5 text-primary" />
                            {favorites.length > 0 && (
                              <span className="absolute -top-1 -right-1 w-2 h-2 bg-red-500 rounded-full border-2 border-white"></span>
                            )}
                          </div>
                          <div className="flex-1">
                            <p className="font-black uppercase tracking-widest text-[10px]">
                              Favoritos
                            </p>
                            <p className="text-[9px] text-on-surface-variant/40 font-bold">
                              Tus anuncios guardados
                            </p>
                          </div>
                          <ChevronRight className="w-4 h-4 text-on-surface-variant/20" />
                        </Link>

                        <Link
                          to="/mensajes"
                          onClick={() => setIsMenuOpen(false)}
                          className="flex items-center gap-4 p-4 bg-surface-container-low rounded-2xl text-on-surface hover:bg-primary/5 hover:text-primary transition-all border border-outline-variant/10 group relative"
                        >
                          <div className="w-10 h-10 bg-white rounded-xl shadow-inner flex items-center justify-center relative">
                            <MessageSquare className="w-5 h-5 text-primary" />
                            {unreadMessagesCount !== undefined &&
                              unreadMessagesCount > 0 && (
                                <span className="absolute -top-1 -right-1 w-2.5 h-2.5 bg-green-500 rounded-full border-2 border-white animate-pulse"></span>
                              )}
                          </div>
                          <div className="flex-1">
                            <p className="font-black uppercase tracking-widest text-[10px]">
                              Mensajes
                            </p>
                            <p className="text-[9px] text-on-surface-variant/40 font-bold">
                              Chat y conversaciones
                            </p>
                          </div>
                          <ChevronRight className="w-4 h-4 text-on-surface-variant/20" />
                        </Link>

                        <button
                          onClick={() => {
                            setIsMenuOpen(false);
                            setIsCalendarModalOpen(true);
                          }}
                          className="flex items-center gap-4 p-4 w-full bg-surface-container-low rounded-2xl text-on-surface hover:bg-primary/5 hover:text-primary transition-all border border-outline-variant/10 group relative text-left"
                        >
                          <div className="w-10 h-10 bg-white rounded-xl shadow-inner flex items-center justify-center">
                            <Calendar className="w-5 h-5 text-primary" />
                          </div>
                          <div className="flex-1">
                            <p className="font-black uppercase tracking-widest text-[10px]">
                              Calendario
                            </p>
                            <p className="text-[9px] text-on-surface-variant/40 font-bold">
                              Planificación de trabajo
                            </p>
                          </div>
                          <ChevronRight className="w-4 h-4 text-on-surface-variant/20" />
                        </button>

                        <Link
                          to="/mis-anuncios"
                          onClick={() => setIsMenuOpen(false)}
                          className="flex items-center gap-4 p-4 bg-surface-container-low rounded-2xl text-on-surface hover:bg-primary/5 hover:text-primary transition-all border border-outline-variant/10 group"
                        >
                          <div className="w-10 h-10 bg-white rounded-xl shadow-inner flex items-center justify-center">
                            <Briefcase className="w-5 h-5 text-primary" />
                          </div>
                          <div className="flex-1">
                            <p className="font-black uppercase tracking-widest text-[10px]">
                              Mis Anuncios
                            </p>
                            <p className="text-[9px] text-on-surface-variant/40 font-bold">
                              Gestionar tus publicaciones
                            </p>
                          </div>
                          <ChevronRight className="w-4 h-4 text-on-surface-variant/20" />
                        </Link>

                        <Link
                          to="/monederos"
                          onClick={() => setIsMenuOpen(false)}
                          className="flex items-center gap-4 p-4 bg-surface-container-low rounded-2xl text-on-surface hover:bg-primary/5 hover:text-primary transition-all border border-outline-variant/10 group"
                        >
                          <div className="w-10 h-10 bg-white rounded-xl shadow-inner flex items-center justify-center">
                            <Wallet className="w-5 h-5 text-primary" />
                          </div>
                          <div className="flex-1">
                            <p className="font-black uppercase tracking-widest text-[10px]">
                              Monedero
                            </p>
                            <p className="text-[9px] text-on-surface-variant/40 font-bold">
                              Pagos y saldo
                            </p>
                          </div>
                          <ChevronRight className="w-4 h-4 text-on-surface-variant/20" />
                        </Link>



                        <button
                          onClick={() => {
                            document.dispatchEvent(
                              new Event("openLanguageModal"),
                            );
                            setIsMenuOpen(false);
                          }}
                          className="w-full flex items-center justify-between p-4 bg-surface-container-low rounded-2xl text-on-surface hover:bg-primary/5 hover:text-primary transition-all border border-outline-variant/10 group mt-2"
                        >
                          <div className="flex items-center gap-4">
                            <div className="w-10 h-10 bg-white rounded-xl shadow-inner flex items-center justify-center">
                              <Globe className="w-5 h-5 text-primary" />
                            </div>
                            <div className="flex-1 text-left">
                              <p className="font-black uppercase tracking-widest text-[10px]">
                                Idioma
                              </p>
                              <p className="text-[9px] text-on-surface-variant/40 font-bold">
                                Cambiar el idioma de la app
                              </p>
                            </div>
                          </div>
                          <ChevronRight className="w-4 h-4 text-on-surface-variant/20" />
                        </button>
                      </div>

                      <button
                        onClick={() => {
                          setSettingsModal({ isOpen: true, type: "" });
                          setIsMenuOpen(false);
                        }}
                        className="w-full flex items-center justify-between px-6 py-4 bg-primary text-white rounded-2xl font-black uppercase tracking-widest text-[10px] shadow-lg shadow-primary/20 mt-4"
                      >
                        <div className="flex items-center gap-3">
                          <Settings className="w-4 h-4" />
                          <span>Configuración de cuenta</span>
                        </div>
                        <ChevronRight className="w-3 h-3 opacity-50" />
                      </button>
                    </div>
                  ) : (
                    <div className="grid grid-cols-1 gap-3">
                      <Link
                        to="/login"
                        onClick={() => setIsMenuOpen(false)}
                        className="flex items-center justify-center gap-4 px-6 py-5 bg-primary text-white rounded-3xl font-black text-xs uppercase tracking-widest transition-all shadow-lg shadow-primary/20"
                      >
                        <User className="w-5 h-5" />
                        Iniciar Sesión
                      </Link>
                      <Link
                        to="/registro"
                        onClick={() => setIsMenuOpen(false)}
                        className="flex items-center justify-center gap-4 px-6 py-5 bg-surface-container-low rounded-3xl text-on-surface font-black text-xs uppercase tracking-widest border border-outline-variant/10 transition-all"
                      >
                        <PlusCircle className="w-5 h-5 text-primary" />
                        Crear Cuenta
                      </Link>
                    </div>
                  )}
                </div>
              </div>
            </motion.div>
          )}
        </AnimatePresence>
        <main
          className={cn(
            isDashboard ? "h-screen pt-16" : "min-h-screen pt-16 pb-16 lg:pb-0",
            isDashboard && "flex flex-1 overflow-hidden",
          )}
        >
          {(() => {
            const activeListings = listings.filter(
              (l) =>
                l &&
                (!l.status || l.status === "active") &&
                (!l.expiresAt || new Date(l.expiresAt) > new Date()),
            );
            return (
              <Routes>
                <Route
                  path="/pagina/:slug"
                  element={
                    <StaticPageView
                      footerConfig={footerConfig}
                      user={user}
                      onSaveConfig={async (newConfig: FooterConfig) => {
                        try {
                          await setDoc(
                            doc(db, "settings", "footer"),
                            newConfig,
                          );
                        } catch (e) {
                          console.error(e);
                          alert("Error al guardar en Firebase");
                        }
                      }}
                    />
                  }
                />
                <Route path="/blog" element={<BlogListPage />} />
                <Route path="/blog/:id" element={<BlogPostPage />} />
                <Route
                  path="/"
                  element={
                    <HomePage
                      listings={activeListings}
                      favorites={favorites}
                      onToggleFavorite={toggleFavorite}
                      search={search}
                      setSearch={setSearch}
                    />
                  }
                />
                <Route
                  path="/explorar"
                  element={
                    <ExplorePage
                      listings={activeListings}
                      favorites={favorites}
                      onToggleFavorite={toggleFavorite}
                    />
                  }
                />
                <Route
                  path="/admin"
                  element={
                    (user?.role === "admin" || user?.email === "daviidjg1991@gmail.com") ? (
                      <AdminPage
                        user={user}
                        listings={listings}
                        setListings={setListings}
                        favorites={favorites}
                        toggleFavorite={toggleFavorite}
                        unreadMessagesCount={unreadMessagesCount}
                      />
                    ) : (
                      <Navigate to="/" replace />
                    )
                  }
                />
                <Route
                  path="/login"
                  element={<AuthPage mode="login" setUser={setUser} />}
                />
                <Route
                  path="/registro"
                  element={<AuthPage mode="register" setUser={setUser} />}
                />

                {/* Dashboard Routes */}
                <Route
                  path="/mensajes"
                  element={
                    <DashboardLayout
                      unreadMessagesCount={unreadMessagesCount}
                      onOpenSettings={(type) =>
                        setSettingsModal({ isOpen: true, type })
                      }
                    >
                      <MessagesPage user={user} />
                    </DashboardLayout>
                  }
                />
                <Route
                  path="/mis-anuncios"
                  element={
                    <DashboardLayout
                      unreadMessagesCount={unreadMessagesCount}
                      onOpenSettings={(type) =>
                        setSettingsModal({ isOpen: true, type })
                      }
                    >
                      <HomePage
                        listings={(listings || []).filter(
                          (l) =>
                            l &&
                            l.author &&
                            l.author.email &&
                            l.author.email ===
                              (user?.email || "guest@example.com") &&
                            l.status !== "deleted",
                        )}
                        favorites={favorites}
                        onToggleFavorite={toggleFavorite}
                        onReactivate={reactivateListing}
                        search={search}
                        setSearch={setSearch}
                      />
                    </DashboardLayout>
                  }
                />
                <Route
                  path="/favoritos"
                  element={
                    <DashboardLayout
                      unreadMessagesCount={unreadMessagesCount}
                      onOpenSettings={(type) =>
                        setSettingsModal({ isOpen: true, type })
                      }
                    >
                      <FavoritesPage
                        listings={activeListings.filter((l) =>
                          favorites.includes(l.id),
                        )}
                        favorites={favorites}
                        onToggleFavorite={toggleFavorite}
                      />
                    </DashboardLayout>
                  }
                />
                <Route
                  path="/estadisticas"
                  element={
                    <DashboardLayout
                      unreadMessagesCount={unreadMessagesCount}
                      onOpenSettings={(type) =>
                        setSettingsModal({ isOpen: true, type })
                      }
                    >
                      <StatsPage user={user} listings={listings} />
                    </DashboardLayout>
                  }
                />
                <Route
                  path="/monederos"
                  element={
                    <DashboardLayout
                      unreadMessagesCount={unreadMessagesCount}
                      onOpenSettings={(type) =>
                        setSettingsModal({ isOpen: true, type })
                      }
                    >
                      <WalletManager isDashboard={true} />
                    </DashboardLayout>
                  }
                />

                {/* Configuración Sub-routes */}
                <Route
                  path="/configuracion/sugerencias"
                  element={
                    <DashboardLayout
                      unreadMessagesCount={unreadMessagesCount}
                      onOpenSettings={(type) =>
                        setSettingsModal({ isOpen: true, type })
                      }
                    >
                      <SettingsSubPage
                        title="Sugerencias Inteligentes"
                        description="Optimiza tu perfil con IA."
                      />
                    </DashboardLayout>
                  }
                />
                <Route
                  path="/configuracion/seguridad"
                  element={
                    <DashboardLayout
                      unreadMessagesCount={unreadMessagesCount}
                      onOpenSettings={(type) =>
                        setSettingsModal({ isOpen: true, type })
                      }
                    >
                      <SettingsSubPage
                        title="Verificaciones y Seguridad"
                        description="Protege tu cuenta."
                      />
                    </DashboardLayout>
                  }
                />
                <Route
                  path="/configuracion/notificaciones"
                  element={
                    <DashboardLayout
                      unreadMessagesCount={unreadMessagesCount}
                      onOpenSettings={(type) =>
                        setSettingsModal({ isOpen: true, type })
                      }
                    >
                      <SettingsSubPage
                        title="Notificaciones"
                        description="Gestiona tus alertas."
                      />
                    </DashboardLayout>
                  }
                />

                <Route
                  path="/anuncio/:id"
                  element={
                    <ListingDetail
                      listings={listings}
                      setListings={setListings}
                      favorites={favorites}
                      onToggleFavorite={toggleFavorite}
                      user={user}
                    />
                  }
                />
                <Route
                  path="/publicar"
                  element={
                    <CreateListing
                      user={user}
                      setUser={setUser}
                      onAdd={addListing}
                      listings={listings}
                      onOpenSettings={(type) =>
                        setSettingsModal({ isOpen: true, type })
                      }
                    />
                  }
                />
                <Route
                  path="/perfil/:id?"
                  element={
                    <ProfilePage
                      user={user}
                      setUser={setUser}
                      listings={listings}
                      favorites={favorites}
                      onToggleFavorite={toggleFavorite}
                      onReactivate={reactivateListing}
                      onOpenSettings={(type) =>
                        setSettingsModal({ isOpen: true, type })
                      }
                    />
                  }
                />

                {/* Catch-all route */}
                <Route path="*" element={<Navigate to="/" replace />} />
              </Routes>
            );
          })()}
        </main>

        {/* Modals */}
        <AnimatePresence></AnimatePresence>

        {/* Mobile Bottom Navigation - Hidden in chats */}
        {location.pathname.includes("/mensajes") &&
        searchParams.has("chatId") ? null : (
          <div className="lg:hidden fixed bottom-0 left-0 right-0 h-16 bg-white border-t border-outline-variant/30 flex items-center justify-around px-2 z-[100] pb-safe shadow-[0_-4px_12px_rgba(0,0,0,0.03)]">
            {[
              { label: "Inicio", icon: Home, path: "/" },
              { label: "Favoritos", icon: Heart, path: "/favoritos" },
              {
                label: "Publicar",
                icon: PlusCircle,
                path: "/publicar",
                isCenter: true,
              },
              {
                label: "Buzón",
                icon: MessageSquare,
                path: "/mensajes",
                badge: unreadMessagesCount,
              },
              {
                label: "Tú",
                icon: User,
                onClick: () => setIsMenuOpen(!isMenuOpen),
                isActive: isMenuOpen,
              },
            ].map((item) => {
              const content = (
                <div
                  className={cn(
                    "flex flex-col items-center gap-1 transition-all",
                    (item.path && location.pathname === item.path) ||
                      item.isActive
                      ? "text-primary"
                      : "text-on-surface-variant/40",
                  )}
                >
                  <div
                    className={cn(
                      "relative",
                      item.isCenter &&
                        "bg-primary text-white p-2.5 rounded-full -mt-8 shadow-xl border-4 border-white",
                    )}
                  >
                    <item.icon className="w-5 h-5" />
                    {"badge" in item && !!item.badge && item.badge > 0 && (
                      <span className="absolute -top-1 -right-1.5 w-4 h-4 bg-green-500 text-white text-[8px] font-black rounded-full flex items-center justify-center border-2 border-white">
                        {item.badge}
                      </span>
                    )}
                  </div>
                  <span
                    className={cn(
                      "text-[9px] font-black uppercase tracking-widest",
                      item.isCenter && "mt-1",
                    )}
                  >
                    {item.label}
                  </span>
                </div>
              );

              if (item.path) {
                return (
                  <Link
                    key={item.label}
                    to={item.path}
                    onClick={(e) => {
                      if (item.label === "Inicio") {
                        e.preventDefault();
                        window.location.href = "/";
                      }
                    }}
                  >
                    {content}
                  </Link>
                );
              }

              return (
                <button key={item.label} onClick={item.onClick}>
                  {content}
                </button>
              );
            })}
          </div>
        )}

        {/* Footer - Hidden on Dashboard */}
        {!isDashboard && (
          <footer className="bg-surface-container-lowest py-16 mt-32 border-t border-outline-variant">
            <div className="max-w-7xl mx-auto px-4 flex flex-col md:flex-row gap-12 lg:gap-24">
              <div className="flex flex-col gap-4 md:w-1/4">
                <div className="flex items-center gap-2">
                  <Briefcase className="w-8 h-8 text-primary" />
                  <span className="text-2xl font-bold tracking-tight text-primary">
                    JobPop
                  </span>
                </div>
                <p className="text-on-surface-variant/60 text-xs font-medium mt-2 leading-relaxed max-w-[200px]">
                  {footerConfig.copyrightText}
                </p>

                {footerConfig.socialLinks &&
                  footerConfig.socialLinks.length > 0 && (
                    <div className="flex flex-wrap items-center gap-3 mt-4">
                      {footerConfig.socialLinks.map((social, idx) => {
                        const Icon =
                          social.platform === "facebook"
                            ? Facebook
                            : social.platform === "twitter"
                              ? Twitter
                              : social.platform === "instagram"
                                ? Instagram
                                : social.platform === "linkedin"
                                  ? Linkedin
                                  : social.platform === "youtube"
                                    ? Youtube
                                    : social.platform === "github"
                                      ? Github
                                      : Globe;

                        const href = social.url.startsWith("http")
                          ? social.url
                          : `https://${social.url}`;
                        return (
                          <a
                            key={idx}
                            href={href}
                            target="_blank"
                            rel="noopener noreferrer"
                            className="p-2 bg-surface-container rounded-full text-on-surface-variant hover:text-primary hover:bg-primary/10 transition-colors"
                          >
                            <Icon className="w-5 h-5" />
                          </a>
                        );
                      })}
                    </div>
                  )}
              </div>

              <div className="grid grid-cols-2 md:grid-cols-4 md:flex-1 gap-8">
                {footerConfig.columns.map((col, idx) => (
                  <div key={idx} className="flex flex-col gap-6">
                    <h4 className="font-bold text-on-surface">{col.title}</h4>
                    <div className="flex flex-col gap-4 text-sm font-medium text-on-surface-variant/70">
                      {col.links.map((link, lidx) => {
                        const url = link.url || "";
                        const isExternal =
                          url.startsWith("http") ||
                          url.startsWith("mailto:") ||
                          url.startsWith("tel:") ||
                          (url.includes(".") &&
                            !url.startsWith("/") &&
                            !url.startsWith("#page-"));

                        if (isExternal) {
                          const href =
                            url.startsWith("http") ||
                            url.startsWith("mailto:") ||
                            url.startsWith("tel:")
                              ? url
                              : `https://${url}`;
                          return (
                            <a
                              key={lidx}
                              href={href}
                              target="_blank"
                              rel="noopener noreferrer"
                              className="hover:text-primary transition-colors"
                            >
                              {link.label}
                            </a>
                          );
                        }

                        // Internal full routes (like /explorar)
                        if (
                          url.startsWith("/") &&
                          !url.startsWith("/pagina/")
                        ) {
                          return (
                            <Link
                              key={lidx}
                              to={url}
                              className="hover:text-primary transition-colors text-left"
                            >
                              {link.label}
                            </Link>
                          );
                        }

                        // Static Pages
                        const normalizedUrl = url.startsWith("#page-")
                          ? url
                          : url.startsWith("/pagina/")
                            ? `#page-${url.replace("/pagina/", "")}`
                            : `#page-${url}`;
                        const slug = normalizedUrl
                          .replace("#page-", "")
                          .replace("/pagina/", "");

                        return (
                          <Link
                            key={lidx}
                            to={`/pagina/${encodeURIComponent(slug)}`}
                            className="hover:text-primary transition-colors text-left"
                          >
                            {link.label}
                          </Link>
                        );
                      })}
                    </div>
                  </div>
                ))}
              </div>
            </div>
          </footer>
        )}
        <AnimatePresence>
          {activeToast && (
            <Toast
              message={activeToast.message}
              type={activeToast.type}
              onClose={() => setActiveToast(null)}
            />
          )}
        </AnimatePresence>

        <AnimatePresence>
          {isPopupOpen && globalPopupConfig && globalPopupConfig.active && (
            <div className="fixed inset-0 z-[300] flex items-center justify-center p-4">
              <motion.div
                initial={{ opacity: 0 }}
                animate={{ opacity: 1 }}
                exit={{ opacity: 0 }}
                onClick={() => setIsPopupOpen(false)}
                className="absolute inset-0 bg-black/60 backdrop-blur-sm"
              />
              <motion.div
                initial={{ opacity: 0, scale: 0.9, y: 20 }}
                animate={{ opacity: 1, scale: 1, y: 0 }}
                exit={{ opacity: 0, scale: 0.9, y: 20 }}
                className="w-full max-w-sm sm:max-w-md rounded-[2.5rem] shadow-[0_24px_64px_-12px_rgba(44,47,48,0.3)] relative overflow-hidden z-10 flex flex-col overflow-y-auto max-h-[90vh] custom-scrollbar"
                style={{
                  backgroundColor:
                    globalPopupConfig.backgroundType === "color"
                      ? globalPopupConfig.backgroundColor
                      : "var(--surface-container-lowest)",
                  backgroundImage:
                    globalPopupConfig.backgroundType !== "color" &&
                    globalPopupConfig.backgroundImageUrl
                      ? `url(${globalPopupConfig.backgroundImageUrl})`
                      : undefined,
                  backgroundSize: "cover",
                  backgroundPosition: "center",
                }}
              >
                {globalPopupConfig.backgroundType !== "color" &&
                  globalPopupConfig.backgroundImageUrl && (
                    <div className="absolute inset-0 bg-surface-container-lowest/80 backdrop-blur-[2px]" />
                  )}
                <div className="relative z-10">
                  <button
                    onClick={() => setIsPopupOpen(false)}
                    className="absolute top-4 right-4 bg-black/10 hover:bg-black/20 text-white rounded-full p-2 transition-colors z-20 backdrop-blur-md"
                  >
                    <X className="w-5 h-5 pointer-events-none" />
                  </button>
                  {globalPopupConfig.imageUrl && (
                    <div className="w-full h-48 sm:h-56 bg-surface-container-low shrink-0 relative">
                      <div className="absolute inset-0 bg-gradient-to-t from-surface-container-lowest via-transparent to-transparent z-10" />
                      <img
                        src={globalPopupConfig.imageUrl}
                        alt="Popup image"
                        className="w-full h-full object-cover"
                      />
                    </div>
                  )}
                  <div
                    className={cn(
                      "p-8 sm:p-10 text-center space-y-4 flex flex-col items-center",
                      !globalPopupConfig.imageUrl && "pt-14",
                    )}
                  >
                    {globalPopupConfig.title && (
                      <div
                        className="font-black font-display tracking-tight text-on-surface [&_br]:block [&_br]:content-[''] [&_br]:my-1"
                        style={{ fontSize: "1.875rem" }}
                        dangerouslySetInnerHTML={{ __html: globalPopupConfig.title }}
                      />
                    )}
                    {globalPopupConfig.description && (
                      <div
                        className="text-on-surface-variant font-medium leading-relaxed"
                        style={{ fontSize: "1rem" }}
                        dangerouslySetInnerHTML={{ __html: globalPopupConfig.description }}
                      />
                    )}

                    {globalPopupConfig.showEmailInput && (
                      <input
                        type="email"
                        placeholder="Tu correo electrónico"
                        value={popupEmail}
                        onChange={(e) => setPopupEmail(e.target.value)}
                        className="w-full p-4 mt-4 rounded-2xl bg-surface-container border border-outline-variant/30 focus:border-primary focus:ring-4 focus:ring-primary/10 outline-none transition-all text-center placeholder:text-on-surface-variant/50 font-bold"
                      />
                    )}

                    {globalPopupConfig.buttonText && (
                      <button
                        onClick={handlePopupSubmit}
                        disabled={isSubmittingPopup}
                        className="w-full bg-primary hover:bg-primary/90 text-white font-black py-4 px-6 rounded-2xl shadow-xl shadow-primary/20 hover:shadow-2xl hover:-translate-y-1 transition-all mt-4 text-sm disabled:opacity-50"
                      >
                        {isSubmittingPopup
                          ? "Enviando..."
                          : globalPopupConfig.buttonText}
                      </button>
                    )}
                  </div>
                </div>
              </motion.div>
            </div>
          )}
        </AnimatePresence>

        <PlanningCalendarModal 
          isOpen={isCalendarModalOpen} 
          onClose={() => setIsCalendarModalOpen(false)} 
          user={user} 
        />
      </div>
    </ReportContext.Provider>
  );
}

export default function Root() {
  return (
    <Router>
      <ErrorBoundary>
        <AppConfigProvider>
          <App />
        </AppConfigProvider>
      </ErrorBoundary>
    </Router>
  );
}
